#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct DestructorQueue {
    entries: Vec<DestructorEntry>,
}

impl DestructorQueue {
    fn register(
        &mut self,
        object: ObjectRef,
        class_name: String,
        function: FunctionId,
        owner_dynamic_unit_index: Option<usize>,
        visibility: DestructorVisibility,
    ) {
        if self
            .entries
            .iter()
            .any(|entry| entry.object.id() == object.id())
        {
            return;
        }
        self.entries.push(DestructorEntry {
            object,
            class_name,
            function,
            owner_dynamic_unit_index,
            visibility,
        });
    }

    fn take_for_object(&mut self, object_id: u64) -> Option<DestructorEntry> {
        let index = self
            .entries
            .iter()
            .position(|entry| entry.object.id() == object_id)?;
        Some(self.entries.remove(index))
    }

    fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

    fn objects_snapshot(&self) -> Vec<ObjectRef> {
        self.entries
            .iter()
            .map(|entry| entry.object.clone())
            .collect()
    }

    fn drain_reverse(&mut self) -> Vec<DestructorEntry> {
        let mut entries = std::mem::take(&mut self.entries);
        entries.reverse();
        entries
    }
}

