    fn call_get_class_methods_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.len() != 1 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: get_class_methods expects one argument",
            );
        }
        let class_name = match class_name_from_object_or_string(&values[0]) {
            Ok(name) => name,
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        if lookup_class_in_state(compiled, state, &class_name).is_none()
            && let Err(result) =
                self.autoload_class(compiled, &class_name, output, stack, state, None)
        {
            return result;
        }
        let Some(class) = lookup_class_in_state(compiled, state, &class_name) else {
            return VmResult::success(output.clone(), Some(Value::Bool(false)));
        };
        let mut array = PhpArray::new();
        for name in visible_class_methods(compiled, stack, state, &class) {
            array.append(Value::string(name));
        }
        VmResult::success(output.clone(), Some(Value::Array(array)))
    }

    fn call_get_class_vars_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.len() != 1 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: get_class_vars expects one class argument",
            );
        }
        let class_name = match to_string(&values[0]) {
            Ok(name) => name.to_string_lossy(),
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        if lookup_class_in_state(compiled, state, &class_name).is_none()
            && let Err(result) =
                self.autoload_class(compiled, &class_name, output, stack, state, None)
        {
            return result;
        }
        let Some(class) = lookup_class_in_state(compiled, state, &class_name) else {
            return VmResult::success(output.clone(), Some(Value::Bool(false)));
        };
        VmResult::success(
            output.clone(),
            Some(Value::Array(visible_class_vars(
                compiled, stack, state, &class,
            ))),
        )
    }

    fn call_user_func_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        let Some(callback) = values.first().cloned() else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALLABLE_ARITY: call_user_func expects at least one argument",
            );
        };
        let args = values
            .into_iter()
            .skip(1)
            .map(CallArgument::positional)
            .collect();
        if let Err(result) = self.preflight_user_callback(
            compiled,
            &callback,
            "call_user_func",
            output,
            stack,
            state,
        ) {
            return result;
        }
        self.call_callable_with_by_ref_value_warnings(
            compiled, callback, args, output, stack, state,
        )
    }

    fn call_user_func_array_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.len() != 2 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALLABLE_ARITY: call_user_func_array expects two arguments",
            );
        }
        let callback = values[0].clone();
        let Value::Array(array) = callable_resolve_reference(values[1].clone()) else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALLABLE_TYPE: call_user_func_array expects array arguments",
            );
        };
        let args = call_args_from_php_array(array);
        if let Err(result) = self.preflight_user_callback(
            compiled,
            &callback,
            "call_user_func_array",
            output,
            stack,
            state,
        ) {
            return result;
        }
        self.call_callable_with_by_ref_value_warnings(
            compiled, callback, args, output, stack, state,
        )
    }

    fn preflight_user_callback(
        &self,
        compiled: &CompiledUnit,
        callback: &Value,
        builtin: &str,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> Result<(), VmResult> {
        match callable_resolve_reference(callback.clone()) {
            Value::String(name) => {
                let name = name.to_string_lossy();
                if let Some((class_name, method)) = name.split_once("::") {
                    self.preflight_static_user_callback(
                        compiled, class_name, method, builtin, output, stack, state,
                    )?;
                }
            }
            Value::Array(array) => {
                let elements = array
                    .iter()
                    .map(|(_, value)| value.clone())
                    .collect::<Vec<_>>();
                let [target, method]: [Value; 2] = match elements.try_into() {
                    Ok(elements) => elements,
                    Err(_) => return Ok(()),
                };
                let Some(method) = callable_string_value(method) else {
                    return Ok(());
                };
                match callable_resolve_reference(target) {
                    Value::Object(object) => self.preflight_object_user_callback(
                        compiled, &object, &method, builtin, output, stack, state,
                    )?,
                    Value::String(class_name) => self.preflight_static_user_callback(
                        compiled,
                        &class_name.to_string_lossy(),
                        &method,
                        builtin,
                        output,
                        stack,
                        state,
                    )?,
                    _ => {}
                }
            }
            _ => {}
        }
        Ok(())
    }

    fn preflight_static_user_callback(
        &self,
        compiled: &CompiledUnit,
        class_name: &str,
        method: &str,
        builtin: &str,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> Result<(), VmResult> {
        let exists = self.class_like_exists_with_autoload_cache(
            compiled,
            class_name,
            AutoloadClassLookupKind::Class,
            true,
            None,
            output,
            stack,
            state,
        )?;
        if !exists {
            return Err(self.callable_type_error(
                compiled,
                output,
                stack,
                state,
                format!(
                    "{builtin}(): Argument #1 ($callback) must be a valid callback, class \"{class_name}\" not found"
                ),
                Some(class_name.to_owned()),
                Some("class"),
            ));
        }
        let Some(resolved) =
            lookup_resolved_method_in_state(compiled, state, class_name, method, None)
                .map_err(|message| self.runtime_error(output, compiled, stack, message))?
        else {
            return Ok(());
        };
        self.preflight_resolved_user_callback(
            compiled,
            &resolved.class,
            &resolved.method,
            builtin,
            output,
            stack,
            state,
        )
    }

    fn preflight_object_user_callback(
        &self,
        compiled: &CompiledUnit,
        object: &ObjectRef,
        method: &str,
        builtin: &str,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> Result<(), VmResult> {
        let Some(resolved) =
            lookup_resolved_method_in_state(compiled, state, &object.class_name(), method, None)
                .map_err(|message| self.runtime_error(output, compiled, stack, message))?
        else {
            return Ok(());
        };
        self.preflight_resolved_user_callback(
            compiled,
            &resolved.class,
            &resolved.method,
            builtin,
            output,
            stack,
            state,
        )
    }

    fn preflight_resolved_user_callback(
        &self,
        compiled: &CompiledUnit,
        class: &php_ir::module::ClassEntry,
        method: &php_ir::module::ClassMethodEntry,
        builtin: &str,
        output: &mut OutputBuffer,
        stack: &CallStack,
        state: &ExecutionState,
    ) -> Result<(), VmResult> {
        let visibility = if method.flags.is_private {
            Some("private")
        } else if method.flags.is_protected {
            Some("protected")
        } else {
            None
        };
        let Some(visibility) = visibility else {
            return Ok(());
        };
        let scope = current_scope_class(compiled, stack);
        let accessible = validate_method_callable_in_state_scope(
            compiled,
            state,
            scope.as_deref(),
            class,
            method,
        )
        .is_ok();
        if accessible {
            return Ok(());
        }
        Err(self.callable_type_error(
            compiled,
            output,
            stack,
            state,
            format!(
                "{builtin}(): Argument #1 ($callback) must be a valid callback, cannot access {visibility} method {}::{}()",
                class.display_name, method.name
            ),
            Some(format!("{}::{}", class.display_name, method.name)),
            Some("function"),
        ))
    }

    fn callable_type_error(
        &self,
        compiled: &CompiledUnit,
        output: &mut OutputBuffer,
        stack: &CallStack,
        state: &ExecutionState,
        message: String,
        requested_name: Option<String>,
        lookup_kind: Option<&'static str>,
    ) -> VmResult {
        self.runtime_error_with_bringup_context(
            output,
            compiled,
            stack,
            state,
            RuntimeSourceSpan::default(),
            format!("E_PHP_RUNTIME_BUILTIN_TYPE: {message}"),
            BringupDiagnosticInput {
                error_class: Some("callable_resolution"),
                requested_name,
                lookup_kind: lookup_kind.or(Some("function")),
                autoload_enabled: Some(true),
                ..BringupDiagnosticInput::default()
            },
        )
    }

    fn call_forward_static_call_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        let Some(callback) = values.first().cloned() else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALLABLE_ARITY: forward_static_call expects at least one argument",
            );
        };
        if current_scope_class(compiled, stack).is_none() {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_INVALID_STATIC_SCOPE: forward_static_call is not available outside class scope",
            );
        }
        let args = values
            .into_iter()
            .skip(1)
            .map(CallArgument::positional)
            .collect();
        self.call_callable(compiled, callback, args, output, stack, state)
    }

    fn call_function_context_builtin(
        &self,
        compiled: &CompiledUnit,
        name: &str,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
    ) -> VmResult {
        if matches!(name, "debug_backtrace" | "debug_print_backtrace") {
            return self.call_debug_backtrace_builtin(compiled, name, values, output, stack);
        }
        let Some(frame) = stack.current() else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                format!("E_PHP_VM_CALL_CONTEXT: {name} is not available outside function scope"),
            );
        };
        let Some(function) = compiled.unit().functions.get(frame.function.index()) else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALL_CONTEXT: missing frame function",
            );
        };
        if function.flags.is_top_level {
            return self.runtime_error(
                output,
                compiled,
                stack,
                format!("E_PHP_VM_CALL_CONTEXT: {name} is not available in top-level scope"),
            );
        }
        match name {
            "func_get_args" => {
                if !values.is_empty() {
                    return self.runtime_error(
                        output,
                        compiled,
                        stack,
                        "E_PHP_VM_CALL_CONTEXT_ARITY: func_get_args expects no arguments",
                    );
                }
                VmResult::success(
                    output.clone(),
                    Some(Value::Array(PhpArray::from_packed(frame.arguments.clone()))),
                )
            }
            "func_num_args" => {
                if !values.is_empty() {
                    return self.runtime_error(
                        output,
                        compiled,
                        stack,
                        "E_PHP_VM_CALL_CONTEXT_ARITY: func_num_args expects no arguments",
                    );
                }
                VmResult::success(
                    output.clone(),
                    Some(Value::Int(frame.arguments.len() as i64)),
                )
            }
            "func_get_arg" => {
                if values.len() != 1 {
                    return self.runtime_error(
                        output,
                        compiled,
                        stack,
                        "E_PHP_VM_CALL_CONTEXT_ARITY: func_get_arg expects one argument",
                    );
                }
                let index = match to_int(&values[0]) {
                    Ok(index) if index >= 0 => index as usize,
                    Ok(_) => {
                        return self.runtime_error(
                            output,
                            compiled,
                            stack,
                            "E_PHP_VM_CALL_CONTEXT_INDEX: func_get_arg index must be non-negative",
                        );
                    }
                    Err(message) => return self.runtime_error(output, compiled, stack, message),
                };
                let Some(value) = frame.arguments.get(index).cloned() else {
                    return self.runtime_error(
                        output,
                        compiled,
                        stack,
                        format!("E_PHP_VM_CALL_CONTEXT_INDEX: func_get_arg index {index} is out of range"),
                    );
                };
                VmResult::success(output.clone(), Some(value))
            }
            _ => self.runtime_error(
                output,
                compiled,
                stack,
                format!("E_PHP_VM_UNKNOWN_CALL_CONTEXT_BUILTIN: {name}"),
            ),
        }
    }

    fn call_debug_backtrace_builtin(
        &self,
        compiled: &CompiledUnit,
        name: &str,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &CallStack,
    ) -> VmResult {
        if values.len() > 2 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                format!("E_PHP_VM_CALL_CONTEXT_ARITY: {name} expects zero to two arguments"),
            );
        }
        let options = match values.first() {
            Some(value) => match to_int(value) {
                Ok(value) => value,
                Err(message) => return self.runtime_error(output, compiled, stack, message),
            },
            None => {
                if name == "debug_backtrace" {
                    1
                } else {
                    0
                }
            }
        };
        let limit = match values.get(1) {
            Some(value) => match to_int(value) {
                Ok(value) if value >= 0 => value as usize,
                Ok(_) => {
                    return self.runtime_error(
                        output,
                        compiled,
                        stack,
                        format!("E_PHP_VM_CALL_CONTEXT_LIMIT: {name} limit must be non-negative"),
                    );
                }
                Err(message) => return self.runtime_error(output, compiled, stack, message),
            },
            None => 0,
        };
        if name == "debug_print_backtrace" {
            let text = capture_debug_print_backtrace_string(compiled, stack, options, limit);
            if !text.is_empty() {
                output.write_test_str(&text);
                output.write_bytes(b"\n");
            }
            return VmResult::success(output.clone(), Some(Value::Null));
        }
        VmResult::success(
            output.clone(),
            Some(Value::Array(debug_backtrace_array(
                compiled, stack, options, limit,
            ))),
        )
    }

    fn call_get_called_class_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &ExecutionState,
    ) -> VmResult {
        if !values.is_empty() {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALL_CONTEXT_ARITY: get_called_class expects no arguments",
            );
        }
        let Some(called_class) = current_called_class(compiled, stack) else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_CALL_CONTEXT: get_called_class is not available outside class scope",
            );
        };
        let display_name = lookup_class_in_state(compiled, state, &called_class)
            .map(|class| class.display_name)
            .unwrap_or(called_class);
        VmResult::success(output.clone(), Some(Value::string(display_name)))
    }

    fn call_is_subclass_of_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if !(2..=3).contains(&values.len()) {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: is_subclass_of expects two or three arguments",
            );
        }
        let allow_string = values
            .get(2)
            .is_none_or(|value| to_bool(value).unwrap_or(true));
        let class_name = match object_from_value(&values[0]) {
            Some(object) => object.class_name(),
            None if allow_string => match to_string(&values[0]) {
                Ok(name) => name.to_string_lossy(),
                Err(message) => return self.runtime_error(output, compiled, stack, message),
            },
            None => return VmResult::success(output.clone(), Some(Value::Bool(false))),
        };
        let target_name = match to_string(&values[1]) {
            Ok(name) => name.to_string_lossy(),
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        for candidate in [&class_name, &target_name] {
            if lookup_class_in_state(compiled, state, candidate).is_none()
                && let Err(result) =
                    self.autoload_class(compiled, candidate, output, stack, state, None)
            {
                return result;
            }
        }
        let exists = class_is_subclass_of_in_state(compiled, state, &class_name, &target_name)
            .unwrap_or(false);
        VmResult::success(output.clone(), Some(Value::Bool(exists)))
    }

    fn call_is_a_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if !(2..=3).contains(&values.len()) {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: is_a expects two or three arguments",
            );
        }
        let allow_string = values
            .get(2)
            .is_some_and(|value| to_bool(value).unwrap_or(false));
        let class_name = match class_name_for_is_a_subject(&values[0], allow_string) {
            Ok(Some(name)) => name,
            Ok(None) => return VmResult::success(output.clone(), Some(Value::Bool(false))),
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        let target_name = match to_string(&values[1]) {
            Ok(name) => name.to_string_lossy(),
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        for candidate in [&class_name, &target_name] {
            if builtin_class_exists(candidate) {
                continue;
            }
            if lookup_class_in_state(compiled, state, candidate).is_none()
                && let Err(result) =
                    self.autoload_class(compiled, candidate, output, stack, state, None)
            {
                return result;
            }
        }
        let exists =
            class_is_a_in_state(compiled, state, &class_name, &target_name).unwrap_or(false);
        VmResult::success(output.clone(), Some(Value::Bool(exists)))
    }

    fn call_get_class_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &ExecutionState,
    ) -> VmResult {
        if values.len() != 1 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: get_class expects one object argument",
            );
        }
        let Some(object) = object_from_value(&values[0]) else {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_TYPE: get_class expects object",
            );
        };
        let class_name = object.class_name();
        let display_name = lookup_class_in_state(compiled, state, &class_name)
            .map(|class| class.display_name)
            .unwrap_or_else(|| object.display_name());
        VmResult::success(output.clone(), Some(Value::string(display_name)))
    }

    fn call_get_parent_class_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.len() != 1 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: get_parent_class expects one argument",
            );
        }
        let class_name = match class_name_from_object_or_string(&values[0]) {
            Ok(name) => name,
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        if lookup_class_in_state(compiled, state, &class_name).is_none()
            && let Err(result) =
                self.autoload_class(compiled, &class_name, output, stack, state, None)
        {
            return result;
        }
        let parent = lookup_class_in_state(compiled, state, &class_name)
            .and_then(|class| class.parent)
            .and_then(|parent| {
                lookup_class_in_state(compiled, state, &parent)
                    .map(|class| class.display_name)
                    .or(Some(parent))
            })
            .map(Value::string)
            .unwrap_or(Value::Bool(false));
        VmResult::success(output.clone(), Some(parent))
    }

    fn call_class_parents_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        call_span: Option<php_ir::IrSpan>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.is_empty() || values.len() > 2 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: class_parents expects one or two arguments",
            );
        }
        let class_name = match class_name_from_object_or_string(&values[0]) {
            Ok(name) => name,
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        let autoload = values
            .get(1)
            .is_none_or(|value| to_bool(value).unwrap_or(true));
        let should_autoload =
            autoload && lookup_class_in_state(compiled, state, &class_name).is_none();
        if should_autoload
            && let Err(result) =
                self.autoload_class(compiled, &class_name, output, stack, state, None)
        {
            return result;
        }
        let Some(class) = lookup_class_in_state(compiled, state, &class_name) else {
            if let Err(result) = self.emit_class_introspection_missing_warning(
                compiled,
                "class_parents",
                &class_name,
                should_autoload,
                call_span,
                output,
                stack,
                state,
            ) {
                return result;
            }
            return VmResult::success(output.clone(), Some(Value::Bool(false)));
        };
        let mut array = PhpArray::new();
        let mut parent = class.parent;
        let mut seen = Vec::new();
        while let Some(parent_name) = parent {
            let normalized = normalize_class_name(&parent_name);
            if seen.iter().any(|name| name == &normalized) {
                break;
            }
            seen.push(normalized.clone());
            let display = lookup_class_in_state(compiled, state, &normalized)
                .map(|class| class.display_name)
                .unwrap_or(parent_name);
            array.insert(string_key(&display), Value::string(display.clone()));
            parent =
                lookup_class_in_state(compiled, state, &normalized).and_then(|class| class.parent);
        }
        VmResult::success(output.clone(), Some(Value::Array(array)))
    }

    fn call_class_implements_builtin(
        &self,
        compiled: &CompiledUnit,
        values: Vec<Value>,
        call_span: Option<php_ir::IrSpan>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> VmResult {
        if values.is_empty() || values.len() > 2 {
            return self.runtime_error(
                output,
                compiled,
                stack,
                "E_PHP_VM_SYMBOL_ARITY: class_implements expects one or two arguments",
            );
        }
        let class_name = match class_name_from_object_or_string(&values[0]) {
            Ok(name) => name,
            Err(message) => return self.runtime_error(output, compiled, stack, message),
        };
        let autoload = values
            .get(1)
            .is_none_or(|value| to_bool(value).unwrap_or(true));
        let should_autoload =
            autoload && lookup_class_in_state(compiled, state, &class_name).is_none();
        if should_autoload
            && let Err(result) =
                self.autoload_class(compiled, &class_name, output, stack, state, None)
        {
            return result;
        }
        let Some(class) = lookup_class_in_state(compiled, state, &class_name) else {
            if let Err(result) = self.emit_class_introspection_missing_warning(
                compiled,
                "class_implements",
                &class_name,
                should_autoload,
                call_span,
                output,
                stack,
                state,
            ) {
                return result;
            }
            return VmResult::success(output.clone(), Some(Value::Bool(false)));
        };
        let mut array = PhpArray::new();
        let mut interfaces = Vec::new();
        collect_class_interface_display_names(compiled, state, &class.name, &mut interfaces);
        for (_, display) in interfaces {
            array.insert(string_key(&display), Value::string(display));
        }
        VmResult::success(output.clone(), Some(Value::Array(array)))
    }

    fn emit_class_introspection_missing_warning(
        &self,
        compiled: &CompiledUnit,
        function_name: &str,
        class_name: &str,
        autoload_attempted: bool,
        call_span: Option<php_ir::IrSpan>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> Result<(), VmResult> {
        let suffix = if autoload_attempted {
            "does not exist and could not be loaded"
        } else {
            "does not exist"
        };
        let message = format!("{function_name}(): Class {class_name} {suffix}");
        let source_span = call_span
            .or_else(|| stack.current().and_then(|frame| frame.call_span))
            .map(|span| runtime_source_span(compiled, span))
            .unwrap_or_default();
        let diagnostic = RuntimeDiagnostic::new(
            "E_PHP_VM_SYMBOL_CLASS_WARNING",
            RuntimeSeverity::Warning,
            message,
            source_span,
            stack_trace(compiled, stack),
            Some(php_runtime::PhpReferenceClassification::Warning),
        );
        let handled = self.dispatch_error_handler(
            compiled,
            output,
            stack,
            state,
            php_runtime::PHP_E_WARNING,
            &diagnostic,
        )?;
        if !handled && error_reporting_allows(state, php_runtime::PHP_E_WARNING) {
            emit_vm_diagnostic(
                output,
                state,
                &diagnostic,
                php_runtime::PhpDiagnosticChannel::Warning,
                php_runtime::PHP_E_WARNING,
            );
            state.diagnostics.push(diagnostic);
        }
        Ok(())
    }

    fn emit_spl_autoload_call_unregister_deprecation(
        &self,
        compiled: &CompiledUnit,
        call_span: Option<php_ir::IrSpan>,
        output: &mut OutputBuffer,
        stack: &mut CallStack,
        state: &mut ExecutionState,
    ) -> Result<(), VmResult> {
        let source_span = call_span
            .or_else(|| stack.current().and_then(|frame| frame.call_span))
            .map(|span| runtime_source_span(compiled, span))
            .unwrap_or_default();
        let diagnostic = RuntimeDiagnostic::new(
            "E_PHP_VM_SPL_AUTOLOAD_CALL_UNREGISTER_DEPRECATED",
            RuntimeSeverity::Deprecation,
            "spl_autoload_unregister(): Using spl_autoload_call() as a callback for spl_autoload_unregister() is deprecated, to remove all registered autoloaders, call spl_autoload_unregister() for all values returned from spl_autoload_functions()"
                .to_owned(),
            source_span,
            stack_trace(compiled, stack),
            None,
        );
        let handled = self.dispatch_error_handler(
            compiled,
            output,
            stack,
            state,
            php_runtime::PHP_E_DEPRECATED,
            &diagnostic,
        )?;
        if !handled && error_reporting_allows(state, php_runtime::PHP_E_DEPRECATED) {
            Self::record_last_error(state, php_runtime::PHP_E_DEPRECATED, &diagnostic);
            emit_vm_diagnostic(
                output,
                state,
                &diagnostic,
                php_runtime::PhpDiagnosticChannel::Deprecated,
                php_runtime::PHP_E_DEPRECATED,
            );
            state.diagnostics.push(diagnostic);
        }
        Ok(())
    }

