fn protected_scope_is_related(
    compiled: &CompiledUnit,
    scope: &str,
    declaring_class: &str,
) -> Result<bool, String> {
    Ok(class_is_or_extends(compiled, scope, declaring_class)?
        || class_is_or_extends(compiled, declaring_class, scope)?)
}

fn protected_scope_is_related_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    scope: &str,
    declaring_class: &str,
) -> Result<bool, String> {
    Ok(
        class_is_a_in_state(compiled, state, scope, declaring_class)?
            || class_is_a_in_state(compiled, state, declaring_class, scope)?,
    )
}

/// Renders the calling scope for access-violation messages: PHP says
/// `"global scope"` outside a class and `"scope Class"` inside one.
fn scope_description(scope: Option<&str>) -> String {
    match scope {
        Some(scope) => format!("scope {scope}"),
        None => "global scope".to_owned(),
    }
}

fn lookup_method_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    if let Some(resolved) =
        lookup_private_method_in_caller_scope(compiled, class, method, caller_scope)?
    {
        return Ok(Some(resolved));
    }
    lookup_method_in_hierarchy_inner(compiled, class, method, caller_scope, &mut Vec::new())
}

fn lookup_private_method_in_caller_scope<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_or_extends(compiled, &class.name, scope)? {
        return Ok(None);
    }
    let Some(scope_class) = compiled.lookup_class(scope) else {
        return Ok(None);
    };
    let normalized = normalize_method_name(method);
    let Some(scope_method) = scope_class
        .methods
        .iter()
        .find(|entry| entry.flags.is_private && normalize_method_name(&entry.name) == normalized)
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedMethod {
        class: scope_class,
        method: scope_method,
    }))
}

fn lookup_method_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    method: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedMethod<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    let normalized = normalize_method_name(method);
    if let Some(method) = class
        .methods
        .iter()
        .find(|entry| normalize_method_name(&entry.name) == normalized)
    {
        if method.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_method) = lookup_method_in_hierarchy_inner(
                compiled,
                parent,
                method.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_method));
        }
        seen.pop();
        return Ok(Some(ResolvedMethod { class, method }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_method_in_hierarchy_inner(compiled, parent, method, caller_scope, seen)?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn parent_class<'a>(
    compiled: &'a CompiledUnit,
    class: &php_ir::module::ClassEntry,
) -> Result<Option<&'a php_ir::module::ClassEntry>, String> {
    let Some(parent) = class.parent.as_deref() else {
        return Ok(None);
    };
    if internal_runtime_parent_is_known(class, parent) {
        return Ok(None);
    }
    if internal_runtime_class_entry(&normalize_class_name(parent)).is_some() {
        return Ok(None);
    }
    compiled.lookup_class(parent).map(Some).ok_or_else(|| {
        format!(
            "E_PHP_VM_UNKNOWN_PARENT_CLASS: class {} extends missing class {}",
            class.name, parent
        )
    })
}

fn lookup_property_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    if let Some(resolved) =
        lookup_private_property_in_caller_scope(compiled, class, property, caller_scope)?
    {
        return Ok(Some(resolved));
    }
    lookup_property_in_hierarchy_inner(compiled, class, property, caller_scope, &mut Vec::new())
}

fn lookup_private_property_in_caller_scope<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    let Some(scope) = caller_scope else {
        return Ok(None);
    };
    if !class_is_or_extends(compiled, &class.name, scope)? {
        return Ok(None);
    }
    let Some(scope_class) = compiled.lookup_class(scope) else {
        return Ok(None);
    };
    let Some(scope_property) = scope_class
        .properties
        .iter()
        .find(|entry| entry.flags.is_private && entry.name == property)
    else {
        return Ok(None);
    };
    Ok(Some(ResolvedProperty {
        class: scope_class,
        property: scope_property,
    }))
}

fn lookup_property_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    property: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedProperty<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    if let Some(entry) = class.properties.iter().find(|entry| entry.name == property) {
        if entry.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_property) = lookup_property_in_hierarchy_inner(
                compiled,
                parent,
                entry.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_property));
        }
        seen.pop();
        return Ok(Some(ResolvedProperty {
            class,
            property: entry,
        }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_property_in_hierarchy_inner(compiled, parent, property, caller_scope, seen)?;
        seen.pop();
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn lookup_constant_in_hierarchy<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    constant: &str,
    caller_scope: Option<&str>,
) -> Result<Option<ResolvedConstant<'a>>, String> {
    lookup_constant_in_hierarchy_inner(compiled, class, constant, caller_scope, &mut Vec::new())
}

fn lookup_constant_in_hierarchy_inner<'a>(
    compiled: &'a CompiledUnit,
    class: &'a php_ir::module::ClassEntry,
    constant: &str,
    caller_scope: Option<&str>,
    seen: &mut Vec<String>,
) -> Result<Option<ResolvedConstant<'a>>, String> {
    let class_name = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &class_name) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(class_name.clone());
    if let Some(entry) = class.constants.iter().find(|entry| entry.name == constant) {
        if entry.flags.is_private
            && caller_scope.is_some_and(|scope| normalize_class_name(scope) != class_name)
            && class.parent.is_some()
            && let Some(parent) = parent_class(compiled, class)?
            && let Some(parent_constant) = lookup_constant_in_hierarchy_inner(
                compiled,
                parent,
                entry.name.as_str(),
                caller_scope,
                seen,
            )?
        {
            seen.pop();
            return Ok(Some(parent_constant));
        }
        seen.pop();
        return Ok(Some(ResolvedConstant {
            class,
            constant: entry,
        }));
    }
    if let Some(parent) = parent_class(compiled, class)? {
        let resolved =
            lookup_constant_in_hierarchy_inner(compiled, parent, constant, caller_scope, seen)?;
        seen.pop();
        if resolved
            .as_ref()
            .is_some_and(|resolved| resolved.constant.flags.is_private)
        {
            return Ok(None);
        }
        return Ok(resolved);
    }
    seen.pop();
    Ok(None)
}

fn validate_property_access(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_ACCESS: Cannot access private property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    if property.flags.is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        };
        if !protected_scope_is_related(compiled, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_property_access_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_ACCESS: Cannot access private property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    if property.flags.is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        };
        if !protected_scope_is_related_in_state(compiled, state, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_ACCESS: Cannot access protected property {}::${}",
                class.display_name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_property_set_access(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.set_is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_SET_ACCESS: property {}::${} setter is private",
                class.name, property.name
            ));
        }
    }
    if property.flags.set_is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        };
        if !protected_scope_is_related(compiled, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_property_set_access_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<(), String> {
    if property.flags.set_is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_PROPERTY_SET_ACCESS: property {}::${} setter is private",
                class.name, property.name
            ));
        }
    }
    if property.flags.set_is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        };
        if !protected_scope_is_related_in_state(compiled, state, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_PROPERTY_SET_ACCESS: property {}::${} setter is protected",
                class.name, property.name
            ));
        }
    }
    Ok(())
}

fn validate_constant_access(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    constant: &php_ir::module::ClassConstantEntry,
) -> Result<(), String> {
    if constant.flags.is_private {
        let scope = current_scope_class(compiled, stack);
        if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
            return Err(format!(
                "E_PHP_VM_PRIVATE_CLASS_CONSTANT_ACCESS: Cannot access private constant {}::{}",
                class.display_name, constant.name
            ));
        }
    }
    if constant.flags.is_protected {
        let Some(scope) = current_scope_class(compiled, stack) else {
            return Err(format!(
                "E_PHP_VM_PROTECTED_CLASS_CONSTANT_ACCESS: Cannot access protected constant {}::{}",
                class.display_name, constant.name
            ));
        };
        if !protected_scope_is_related(compiled, &scope, &class.name)? {
            return Err(format!(
                "E_PHP_VM_PROTECTED_CLASS_CONSTANT_ACCESS: Cannot access protected constant {}::{}",
                class.display_name, constant.name
            ));
        }
    }
    Ok(())
}

fn validate_property_write(
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    object: &ObjectRef,
    stack: &CallStack,
    compiled: &CompiledUnit,
) -> Result<(), String> {
    if !(property.flags.is_readonly || class.flags.is_readonly) {
        return Ok(());
    }
    let scope = current_scope_class(compiled, stack);
    if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
        return Err(format!(
            "E_PHP_VM_READONLY_PROPERTY_WRITE: property {}::${} is readonly",
            class.name, property.name
        ));
    }
    let storage_name = property_storage_name(class, property);
    if !matches!(
        object.get_property(&storage_name),
        None | Some(Value::Uninitialized)
    ) {
        return Err(format!(
            "E_PHP_VM_READONLY_PROPERTY_WRITE: property {}::${} is already initialized",
            class.name, property.name
        ));
    }
    Ok(())
}

fn property_state_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    object: &ObjectRef,
    property: &str,
) -> Option<Value> {
    let Some(class) = lookup_class_in_state(compiled, state, &object.class_name()) else {
        return object.get_property(property);
    };
    let scope = current_scope_class(compiled, stack);
    let Some(resolved) =
        lookup_resolved_property_in_state(compiled, state, &class, property, scope.as_deref())
            .ok()?
    else {
        return object.get_property(property);
    };
    if validate_property_access_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.property,
    )
    .is_err()
    {
        return None;
    }
    let storage_name = property_storage_name(&resolved.class, &resolved.property);
    object
        .get_property(&storage_name)
        .or_else(|| object.get_property(property))
}

fn property_dimension_storage_name(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    object: &ObjectRef,
    property: &str,
    write: bool,
) -> Result<String, String> {
    let Some(class) = lookup_class_in_state(compiled, state, &object.class_name()) else {
        return Ok(property.to_owned());
    };
    let scope = current_scope_class(compiled, stack);
    let Some(resolved) =
        lookup_resolved_property_in_state(compiled, state, &class, property, scope.as_deref())?
    else {
        return Ok(property.to_owned());
    };
    validate_property_access_in_state(compiled, state, stack, &resolved.class, &resolved.property)?;
    if write {
        validate_property_set_access_in_state(
            compiled,
            state,
            stack,
            &resolved.class,
            &resolved.property,
        )?;
        validate_property_write(&resolved.class, &resolved.property, object, stack, compiled)?;
        if resolved.property.flags.is_static {
            return Err(format!(
                "E_PHP_VM_NON_STATIC_PROPERTY_ACCESS: property {}::${} is static",
                resolved.class.name, resolved.property.name
            ));
        }
        if !resolved.property.hooks.backed
            && (resolved.property.hooks.get.is_some() || resolved.property.hooks.set.is_some())
        {
            return Err(format!(
                "E_PHP_VM_VIRTUAL_PROPERTY_WRITE: property {}::${} has no backing storage",
                resolved.class.name, resolved.property.name
            ));
        }
    }
    Ok(property_storage_name(&resolved.class, &resolved.property))
}

fn unset_property_dim(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    object: &ObjectRef,
    property: &str,
    dims: &[ArrayKey],
) -> Result<(), String> {
    let storage_name =
        property_dimension_storage_name(compiled, state, stack, object, property, true)?;
    let Some(mut current) = object
        .get_property(&storage_name)
        .or_else(|| object.get_property(property))
    else {
        return Ok(());
    };
    unset_dim_value(&mut current, dims);
    object.set_property(storage_name, current);
    Ok(())
}

fn magic_property_call_is_active(
    state: &ExecutionState,
    object: &ObjectRef,
    method: &str,
    property: &str,
) -> bool {
    let guard = MagicPropertyCall {
        object_id: object.id(),
        method: normalize_method_name(method),
        property: property.to_owned(),
    };
    state
        .magic_property_stack
        .iter()
        .any(|active| active == &guard)
}

fn ensure_property_reference_cell(
    compiled: &CompiledUnit,
    stack: &CallStack,
    object: &ObjectRef,
    property: &str,
) -> Result<ReferenceCell, String> {
    let storage_name = if let Some(class) = compiled.lookup_class(&object.class_name()) {
        let scope = current_scope_class(compiled, stack);
        if let Some(resolved) =
            lookup_property_in_hierarchy(compiled, class, property, scope.as_deref())?
        {
            validate_property_access(compiled, stack, resolved.class, resolved.property)?;
            validate_property_set_access(compiled, stack, resolved.class, resolved.property)?;
            property_storage_name(resolved.class, resolved.property)
        } else {
            property.to_owned()
        }
    } else {
        property.to_owned()
    };
    if object.get_property(&storage_name).is_none()
        && let Some(value) = object.get_property(property)
    {
        object.set_property(storage_name.clone(), value);
    }
    Lvalue::object_property(object.clone(), storage_name, LvalueKind::ObjectProperty)
        .ensure_reference_cell()
        .map_err(|error| error.to_string())
}

fn ensure_property_dim_reference_cell(
    compiled: &CompiledUnit,
    stack: &CallStack,
    object: &ObjectRef,
    property: &str,
    dims: &[ArrayKey],
) -> Result<ReferenceCell, String> {
    let property_cell = ensure_property_reference_cell(compiled, stack, object, property)?;
    let mut current = property_cell.get();
    if matches!(current, Value::Uninitialized | Value::Null) {
        current = Value::Array(PhpArray::new());
    }
    let cell = ensure_dim_reference_cell_value(&mut current, dims)?;
    property_cell.set(current);
    Ok(cell)
}

fn validate_static_property_write(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    current: &Value,
) -> Result<(), String> {
    if !(property.flags.is_readonly || class.flags.is_readonly) {
        return Ok(());
    }
    let scope = current_scope_class(compiled, stack);
    if scope.as_deref() != Some(normalize_class_name(&class.name).as_str()) {
        return Err(format!(
            "E_PHP_VM_READONLY_STATIC_PROPERTY_WRITE: property {}::${} is readonly",
            class.name, property.name
        ));
    }
    if !matches!(current, Value::Uninitialized) {
        return Err(format!(
            "E_PHP_VM_READONLY_STATIC_PROPERTY_WRITE: property {}::${} is already initialized",
            class.name, property.name
        ));
    }
    Ok(())
}

fn static_property_key(
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> (String, String) {
    (normalize_class_name(&class.name), property.name.clone())
}

fn write_static_property_lvalue(
    static_properties: &mut HashMap<(String, String), Value>,
    key: (String, String),
    default: Value,
    value: Value,
) -> Result<(), String> {
    let entry = static_properties.entry(key).or_insert(default);
    Lvalue::value(entry, LvalueKind::StaticProperty)
        .write_value(value)
        .map_err(|error| error.to_string())
}

fn bind_static_property_lvalue(
    static_properties: &mut HashMap<(String, String), Value>,
    key: (String, String),
    default: Value,
    cell: ReferenceCell,
) -> Result<(), String> {
    let entry = static_properties.entry(key).or_insert(default);
    Lvalue::value(entry, LvalueKind::StaticProperty)
        .bind_reference_cell(cell)
        .map_err(|error| error.to_string())
}

fn ensure_static_property_dim_reference_cell(
    static_properties: &mut HashMap<(String, String), Value>,
    key: (String, String),
    default: Value,
    dims: &[ArrayKey],
) -> Result<ReferenceCell, String> {
    let entry = static_properties.entry(key).or_insert(default);
    if dims.is_empty() {
        return Lvalue::value(entry, LvalueKind::StaticProperty)
            .ensure_reference_cell()
            .map_err(|error| error.to_string());
    }
    if matches!(entry, Value::Uninitialized | Value::Null) {
        *entry = Value::Array(PhpArray::new());
    }
    ensure_dim_reference_cell_value(entry, dims)
}

fn static_property_default(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> Result<Value, String> {
    if let Some(default) = property.default {
        let owner = class_owner_in_state(compiled, state, &class.name);
        runtime_constant_value(compiled, state, stack, owner.unit(), default)
    } else if let Some(reference) = &property.default_class_constant {
        class_constant_reference_value(compiled, state, reference)
    } else if let Some(reference) = &property.default_named_constant {
        named_constant_reference_value(compiled, state, reference)
    } else if let Some(expr) = &property.default_expr {
        deferred_const_expr_value(compiled, state, expr)
    } else if property.flags.is_typed {
        Ok(Value::Uninitialized)
    } else {
        Ok(Value::Null)
    }
}

fn runtime_constant_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    unit: &IrUnit,
    constant: ConstId,
) -> Result<Value, String> {
    let Some(value) = unit.constants.get(constant.index()) else {
        return Err(format!("invalid constant const:{}", constant.raw()));
    };
    runtime_inline_constant_value(compiled, state, stack, value)
}

fn runtime_inline_constant_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    constant: &IrConstant,
) -> Result<Value, String> {
    match constant {
        IrConstant::Null => Ok(Value::Null),
        IrConstant::Bool(value) => Ok(Value::Bool(*value)),
        IrConstant::Int(value) => Ok(Value::Int(*value)),
        IrConstant::Float(value) => Ok(Value::float(*value)),
        IrConstant::String(value) => Ok(Value::String(PhpString::from_test_str(value))),
        IrConstant::StringBytes(value) => Ok(Value::String(PhpString::from_bytes(value.clone()))),
        IrConstant::NamedConstant(name) => lexical_constant_value(compiled, state, stack, name)?
            .ok_or_else(|| format!("E_PHP_VM_UNDEFINED_CONSTANT: constant {name} is not defined")),
        IrConstant::ClassConstant {
            class_name,
            constant_name,
        } => class_constant_value_by_name(
            compiled,
            state,
            stack,
            &format!("{class_name}::{constant_name}"),
        )?
        .ok_or_else(|| {
            format!(
                "E_PHP_VM_UNDEFINED_CLASS_CONSTANT: constant {class_name}::{constant_name} is not defined"
            )
        }),
        IrConstant::Array(entries) => {
            let mut array = PhpArray::new();
            for entry in entries {
                let value = runtime_inline_constant_value(compiled, state, stack, &entry.value)?;
                if let Some(key) = &entry.key {
                    let key_value = runtime_inline_constant_value(compiled, state, stack, key)?;
                    if let Some(key) = ArrayKey::from_value(&key_value) {
                        array.insert(key, value);
                    } else {
                        array.append(value);
                    }
                } else {
                    array.append(value);
                }
            }
            Ok(Value::Array(array))
        }
    }
}

fn deferred_const_expr_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    expr: &DeferredConstExpr,
) -> Result<Value, String> {
    match expr {
        DeferredConstExpr::Literal(value) => Ok(inline_constant_value(value)),
        DeferredConstExpr::NamedConstant(reference) => {
            named_constant_reference_value(compiled, state, reference)
        }
        DeferredConstExpr::ClassConstant(reference) => {
            class_constant_reference_value(compiled, state, reference)
        }
        DeferredConstExpr::Array(entries) => {
            let mut array = PhpArray::new();
            for entry in entries {
                let value = deferred_const_expr_value(compiled, state, &entry.value)?;
                if let Some(key) = &entry.key {
                    let key_value = deferred_const_expr_value(compiled, state, key)?;
                    if let Some(key) = ArrayKey::from_value(&key_value) {
                        array.insert(key, value);
                    } else {
                        array.append(value);
                    }
                } else {
                    array.append(value);
                }
            }
            Ok(Value::Array(array))
        }
    }
}

enum StaticPropertyIssetEmptyError {
    Runtime(String),
    Vm(Box<VmResult>),
}

impl From<String> for StaticPropertyIssetEmptyError {
    fn from(message: String) -> Self {
        Self::Runtime(message)
    }
}

fn static_property_isset_empty_result(
    vm: &Vm,
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &mut CallStack,
    class_name: &str,
    property: &str,
    is_empty: bool,
    span: IrSpan,
    call_site: Option<(u64, FunctionId, BlockId, InstrId)>,
    output: &mut OutputBuffer,
) -> Result<bool, StaticPropertyIssetEmptyError> {
    vm.autoload_static_class_if_missing(
        compiled, class_name, span, call_site, output, stack, state,
    )
    .map_err(|result| StaticPropertyIssetEmptyError::Vm(Box::new(result)))?;
    let class = resolve_static_class_name(compiled, state, stack, class_name)?;
    let scope = current_scope_class(compiled, stack);
    let Some(resolved) =
        lookup_resolved_property_in_state(compiled, state, &class, property, scope.as_deref())?
    else {
        return Ok(is_empty);
    };
    if !resolved.property.flags.is_static {
        return Err(StaticPropertyIssetEmptyError::Runtime(format!(
            "E_PHP_VM_NON_STATIC_PROPERTY_ACCESS: property {}::${} is not static",
            resolved.class.name, resolved.property.name
        )));
    }
    if validate_property_access_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.property,
    )
    .is_err()
    {
        return Ok(is_empty);
    }
    let key = static_property_key(&resolved.class, &resolved.property);
    if !state.static_properties.contains_key(&key) {
        let default =
            static_property_default(compiled, state, stack, &resolved.class, &resolved.property)?;
        state.static_properties.insert(key.clone(), default);
    }
    let value = state
        .static_properties
        .get(&key)
        .cloned()
        .unwrap_or(Value::Uninitialized);
    if is_empty {
        Ok(php_empty(&value)?)
    } else {
        Ok(!matches!(value, Value::Uninitialized | Value::Null))
    }
}

fn static_property_dim_isset_empty_result(
    vm: &Vm,
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &mut CallStack,
    class_name: &str,
    property: &str,
    dims: &[ArrayKey],
    is_empty: bool,
    span: IrSpan,
    call_site: Option<(u64, FunctionId, BlockId, InstrId)>,
    output: &mut OutputBuffer,
) -> Result<bool, StaticPropertyIssetEmptyError> {
    vm.autoload_static_class_if_missing(
        compiled, class_name, span, call_site, output, stack, state,
    )
    .map_err(|result| StaticPropertyIssetEmptyError::Vm(Box::new(result)))?;
    let class = resolve_static_class_name(compiled, state, stack, class_name)?;
    let scope = current_scope_class(compiled, stack);
    let Some(resolved) =
        lookup_resolved_property_in_state(compiled, state, &class, property, scope.as_deref())?
    else {
        return Ok(is_empty);
    };
    if !resolved.property.flags.is_static {
        return Err(StaticPropertyIssetEmptyError::Runtime(format!(
            "E_PHP_VM_NON_STATIC_PROPERTY_ACCESS: property {}::${} is not static",
            resolved.class.name, resolved.property.name
        )));
    }
    if validate_property_access_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.property,
    )
    .is_err()
    {
        return Ok(is_empty);
    }
    let key = static_property_key(&resolved.class, &resolved.property);
    if !state.static_properties.contains_key(&key) {
        let default =
            static_property_default(compiled, state, stack, &resolved.class, &resolved.property)?;
        state.static_properties.insert(key.clone(), default);
    }
    let value = state
        .static_properties
        .get(&key)
        .cloned()
        .unwrap_or(Value::Uninitialized);
    let value = fetch_dim_path_value(&value, dims)
        .ok()
        .flatten()
        .unwrap_or(Value::Uninitialized);
    if is_empty {
        Ok(php_empty(&value)?)
    } else {
        Ok(!matches!(value, Value::Uninitialized | Value::Null))
    }
}

fn static_property_dim_unset_result(
    vm: &Vm,
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &mut CallStack,
    class_name: &str,
    property: &str,
    dims: &[ArrayKey],
    span: IrSpan,
    call_site: Option<(u64, FunctionId, BlockId, InstrId)>,
    output: &mut OutputBuffer,
) -> Result<(), StaticPropertyIssetEmptyError> {
    vm.autoload_static_class_if_missing(
        compiled, class_name, span, call_site, output, stack, state,
    )
    .map_err(|result| StaticPropertyIssetEmptyError::Vm(Box::new(result)))?;
    let class = resolve_static_class_name(compiled, state, stack, class_name)?;
    let scope = current_scope_class(compiled, stack);
    let Some(resolved) =
        lookup_resolved_property_in_state(compiled, state, &class, property, scope.as_deref())?
    else {
        return Ok(());
    };
    if !resolved.property.flags.is_static {
        return Err(StaticPropertyIssetEmptyError::Runtime(format!(
            "E_PHP_VM_NON_STATIC_PROPERTY_ACCESS: property {}::${} is not static",
            resolved.class.name, resolved.property.name
        )));
    }
    validate_property_access_in_state(compiled, state, stack, &resolved.class, &resolved.property)?;
    validate_property_set_access_in_state(
        compiled,
        state,
        stack,
        &resolved.class,
        &resolved.property,
    )?;
    let key = static_property_key(&resolved.class, &resolved.property);
    let mut current = if let Some(value) = state.static_properties.get(&key) {
        value.clone()
    } else {
        static_property_default(compiled, state, stack, &resolved.class, &resolved.property)?
    };
    validate_static_property_write(
        compiled,
        stack,
        &resolved.class,
        &resolved.property,
        &current,
    )?;
    unset_dim_value(&mut current, dims);
    state.static_properties.insert(key, current);
    Ok(())
}

fn resolve_static_class_name(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    class_name: &str,
) -> Result<php_ir::module::ClassEntry, String> {
    match normalize_class_name(class_name).as_str() {
        "self" => {
            let Some(scope) = current_scope_class(compiled, stack) else {
                return Err(format!(
                    "E_PHP_VM_INVALID_STATIC_SCOPE: {class_name}:: is not available outside class scope"
                ));
            };
            lookup_class_in_state(compiled, state, &scope)
                .ok_or_else(|| format!("E_PHP_VM_UNKNOWN_CLASS: class {scope} is not defined"))
        }
        "static" => {
            let Some(called) = current_called_class_display(compiled, stack)
                .or_else(|| current_scope_class(compiled, stack))
            else {
                return Err(
                    "E_PHP_VM_INVALID_STATIC_SCOPE: static:: is not available outside class scope"
                        .to_owned(),
                );
            };
            lookup_class_in_state(compiled, state, &called)
                .or_else(|| current_this_called_class(compiled, state, stack, &called))
                .ok_or_else(|| format!("E_PHP_VM_UNKNOWN_CLASS: class {called} is not defined"))
        }
        "parent" => {
            let Some(scope) = current_scope_class(compiled, stack) else {
                return Err(
                    "E_PHP_VM_INVALID_STATIC_SCOPE: parent:: is not available outside class scope"
                        .to_owned(),
                );
            };
            let Some(class) = lookup_class_in_state(compiled, state, &scope) else {
                return Err(format!(
                    "E_PHP_VM_UNKNOWN_CLASS: class {scope} is not defined"
                ));
            };
            if let Some(parent) = class.parent.as_deref()
                && let Some(parent) = internal_runtime_class_entry(&normalize_class_name(parent))
            {
                return Ok(parent);
            }
            let Some(parent_name) = class.parent.as_deref() else {
                return Err(format!(
                    "E_PHP_VM_NO_PARENT_CLASS: class {} has no parent",
                    class.name
                ));
            };
            lookup_class_in_state(compiled, state, parent_name).ok_or_else(|| {
                format!(
                    "E_PHP_VM_UNKNOWN_PARENT_CLASS: class {} extends missing class {}",
                    class.name, parent_name
                )
            })
        }
        _ => lookup_class_in_state(compiled, state, class_name)
            .or_else(|| internal_runtime_class_entry(&normalize_class_name(class_name)))
            .ok_or_else(|| format!("E_PHP_VM_UNKNOWN_CLASS: class {class_name} is not defined")),
    }
}

fn is_special_static_class_name(class_name: &str) -> bool {
    matches!(
        normalize_class_name(class_name).as_str(),
        "self" | "static" | "parent"
    )
}

fn static_class_autoload_name(compiled: &CompiledUnit, class_name: &str, span: IrSpan) -> String {
    let display_name = display_class_name(class_name);
    static_class_name_from_source_span(compiled, span)
        .filter(|source_name| normalize_class_name(source_name) == normalize_class_name(class_name))
        .unwrap_or(display_name)
}

fn static_class_name_from_source_span(compiled: &CompiledUnit, span: IrSpan) -> Option<String> {
    if span == IrSpan::default() {
        return None;
    }
    let file = compiled.unit().files.get(span.file.index())?;
    let source = fs::read_to_string(&file.path).ok()?;
    let start = usize::try_from(span.start).ok()?;
    let end = usize::try_from(span.end).ok()?.min(source.len());
    if start >= end || start >= source.len() || !source.is_char_boundary(start) {
        return None;
    }
    let end = if source.is_char_boundary(end) {
        end
    } else {
        source[..end].char_indices().last()?.0
    };
    let slice = source.get(start..end)?;
    let before_static_access = slice.split_once("::")?.0.trim_end();
    let name_start = before_static_access
        .char_indices()
        .rev()
        .find_map(|(index, ch)| (!is_php_class_name_char(ch)).then_some(index + ch.len_utf8()))
        .unwrap_or(0);
    let candidate = before_static_access
        .get(name_start..)?
        .trim_start_matches('\\');
    (!candidate.is_empty() && !is_special_static_class_name(candidate))
        .then(|| candidate.to_owned())
}

fn is_php_class_name_char(ch: char) -> bool {
    ch == '\\' || ch == '_' || ch.is_ascii_alphanumeric()
}

fn called_class_for_static_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class_name: &str,
    resolved_class: &php_ir::module::ClassEntry,
) -> String {
    match normalize_class_name(class_name).as_str() {
        "self" | "static" | "parent" => current_called_class_display(compiled, stack)
            .or_else(|| current_scope_class_display(compiled, stack))
            .unwrap_or_else(|| resolved_class.display_name.clone()),
        _ => resolved_class.display_name.clone(),
    }
}

fn method_lookup_scope_for_static_call(
    compiled: &CompiledUnit,
    stack: &CallStack,
    class_name: &str,
) -> Option<String> {
    if normalize_class_name(class_name) == "static" {
        None
    } else {
        current_scope_class(compiled, stack)
    }
}

fn current_scope_class(compiled: &CompiledUnit, stack: &CallStack) -> Option<String> {
    current_scope_class_display(compiled, stack).map(|class| normalize_class_name(&class))
}

fn current_scope_class_display(compiled: &CompiledUnit, stack: &CallStack) -> Option<String> {
    let frame = stack.current()?;
    if let Some(scope) = frame.scope_class.as_deref() {
        return Some(scope.to_owned());
    }
    let function = compiled.unit().functions.get(frame.function.index())?;
    function
        .flags
        .is_method
        .then(|| {
            function
                .name
                .split_once("::")
                .map(|(class, _)| class.to_owned())
        })
        .flatten()
}

fn current_this_object(compiled: &CompiledUnit, stack: &CallStack) -> Option<ObjectRef> {
    let frame = stack.current()?;
    let function = compiled.unit().functions.get(frame.function.index())?;
    let local = function
        .locals
        .iter()
        .position(|name| name == "this")
        .map(|index| LocalId::new(index as u32))?;
    match frame.locals.get(local)? {
        Value::Object(object) => Some(object),
        _ => None,
    }
}

fn current_called_class(compiled: &CompiledUnit, stack: &CallStack) -> Option<String> {
    current_called_class_display(compiled, stack).map(|class| normalize_class_name(&class))
}

fn current_called_class_display(compiled: &CompiledUnit, stack: &CallStack) -> Option<String> {
    let frame = stack.current()?;
    frame
        .called_class
        .as_deref()
        .map(ToOwned::to_owned)
        .or_else(|| current_scope_class_display(compiled, stack))
}

fn current_this_called_class(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
    called_display: &str,
) -> Option<php_ir::module::ClassEntry> {
    let this_value = current_this_object(compiled, stack)?;
    (normalize_class_name(&this_value.display_name()) == normalize_class_name(called_display))
        .then(|| lookup_class_in_state(compiled, state, &this_value.class_name()))
        .flatten()
}

fn class_is_or_extends(
    compiled: &CompiledUnit,
    class_name: &str,
    ancestor_name: &str,
) -> Result<bool, String> {
    let ancestor_name = normalize_class_name(ancestor_name);
    let Some(mut class) = compiled.lookup_class(class_name) else {
        return Ok(false);
    };
    let mut seen = Vec::new();
    loop {
        let current = normalize_class_name(&class.name);
        if current == ancestor_name {
            return Ok(true);
        }
        if seen.iter().any(|name| name == &current) {
            return Err(format!(
                "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
                class.name
            ));
        }
        seen.push(current);
        if let Some(parent) = class.parent.as_deref() {
            let parent = normalize_class_name(parent);
            if internal_runtime_class_entry(&parent).is_some() {
                return Ok(internal_runtime_class_is_or_extends(
                    &parent,
                    &ancestor_name,
                ));
            }
        }
        let Some(parent) = parent_class(compiled, class)? else {
            return Ok(false);
        };
        class = parent;
    }
}

fn class_is_or_implements(
    compiled: &CompiledUnit,
    class_name: &str,
    target_name: &str,
) -> Result<bool, String> {
    if class_is_or_extends(compiled, class_name, target_name)? {
        return Ok(true);
    }
    class_implements_interface(compiled, class_name, target_name, &mut Vec::new())
}

fn internal_runtime_parent_name(class_name: &str) -> Option<String> {
    let class_name = normalize_class_name(class_name);
    if is_spl_iterator_runtime_class(&class_name) {
        match class_name.as_str() {
            "recursivearrayiterator" => Some(normalize_class_name("ArrayIterator")),
            _ => spl_iterator_class(&class_name).parent,
        }
    } else if is_spl_container_runtime_class(&class_name) {
        spl_container_class(&class_name).parent
    } else if is_spl_heap_runtime_class(&class_name) {
        spl_heap_class(&class_name).parent
    } else if is_spl_file_runtime_class(&class_name) {
        spl_file_class(&class_name).parent
    } else if internal_throwable_instanceof(&class_name, "throwable").is_some() {
        internal_throwable_parent(&class_name).map(normalize_class_name)
    } else {
        None
    }
}

fn internal_runtime_class_is_or_extends(class_name: &str, ancestor_name: &str) -> bool {
    let mut class_name = normalize_class_name(class_name);
    let ancestor_name = normalize_class_name(ancestor_name);
    let mut seen = Vec::new();
    loop {
        if class_name == ancestor_name {
            return true;
        }
        if seen.iter().any(|name| name == &class_name) {
            return false;
        }
        seen.push(class_name.clone());
        let parent = internal_runtime_parent_name(&class_name);
        let Some(parent) = parent else {
            return false;
        };
        class_name = parent;
    }
}

fn class_implements_interface(
    compiled: &CompiledUnit,
    class_name: &str,
    interface_name: &str,
    seen: &mut Vec<String>,
) -> Result<bool, String> {
    let interface_name = normalize_class_name(interface_name);
    let Some(class) = compiled.lookup_class(class_name) else {
        return Ok(false);
    };
    let current = normalize_class_name(&class.name);
    if seen.iter().any(|name| name == &current) {
        return Err(format!(
            "E_PHP_VM_CLASS_INHERITANCE_CYCLE: class {} participates in an inheritance cycle",
            class.name
        ));
    }
    seen.push(current);
    for interface in &class.interfaces {
        if interface_or_extends(compiled, interface, &interface_name, &mut Vec::new())? {
            seen.pop();
            return Ok(true);
        }
    }
    if let Some(parent) = class.parent.as_deref() {
        let parent = normalize_class_name(parent);
        if internal_runtime_class_entry(&parent).is_some() {
            if interface_or_extends(compiled, &parent, &interface_name, &mut Vec::new())? {
                seen.pop();
                return Ok(true);
            }
            for interface in internal_class_interfaces(&parent) {
                if interface_or_extends(compiled, &interface, &interface_name, &mut Vec::new())? {
                    seen.pop();
                    return Ok(true);
                }
            }
        }
    }
    if let Some(parent) = parent_class(compiled, class)?
        && class_implements_interface(compiled, &parent.name, &interface_name, seen)?
    {
        seen.pop();
        return Ok(true);
    }
    seen.pop();
    Ok(false)
}

fn collect_class_interface_display_names(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    class_name: &str,
    seen: &mut Vec<(String, String)>,
) {
    let normalized = normalize_class_name(class_name);
    let Some(class) = lookup_class_in_state(compiled, state, &normalized) else {
        for interface in internal_class_interfaces(&normalized) {
            collect_interface_display_names(compiled, &interface, seen);
        }
        if let Some(parent) = internal_runtime_parent_name(&normalized) {
            collect_class_interface_display_names(compiled, state, &parent, seen);
        }
        return;
    };
    for interface in &class.interfaces {
        collect_interface_display_names(compiled, interface, seen);
    }
    if let Some(parent) = class.parent.as_deref() {
        collect_class_interface_display_names(compiled, state, parent, seen);
    }
}

fn collect_interface_display_names(
    compiled: &CompiledUnit,
    interface_name: &str,
    seen: &mut Vec<(String, String)>,
) {
    let normalized = normalize_class_name(interface_name);
    if seen.iter().any(|(name, _)| name == &normalized) {
        return;
    }
    let display = compiled
        .lookup_class(&normalized)
        .map(|class| class.display_name.clone())
        .unwrap_or_else(|| interface_name.to_owned());
    seen.push((normalized.clone(), display));
    if let Some(interface) = compiled.lookup_class(&normalized) {
        for parent in &interface.interfaces {
            collect_interface_display_names(compiled, parent, seen);
        }
    } else {
        for parent in internal_class_interfaces(&normalized) {
            collect_interface_display_names(compiled, &parent, seen);
        }
    }
}

fn interface_or_extends(
    compiled: &CompiledUnit,
    interface_name: &str,
    target_name: &str,
    seen: &mut Vec<String>,
) -> Result<bool, String> {
    let interface_name = normalize_class_name(interface_name);
    let target_name = normalize_class_name(target_name);
    if interface_name == target_name {
        return Ok(true);
    }
    let Some(interface) = compiled.lookup_class(&interface_name) else {
        for parent in internal_class_interfaces(&interface_name) {
            if interface_or_extends(compiled, &parent, &target_name, seen)? {
                return Ok(true);
            }
        }
        return Ok(false);
    };
    if seen.iter().any(|name| name == &interface_name) {
        return Err(format!(
            "E_PHP_VM_INTERFACE_INHERITANCE_CYCLE: interface {} participates in an inheritance cycle",
            interface.name
        ));
    }
    seen.push(interface_name);
    for parent in &interface.interfaces {
        if interface_or_extends(compiled, parent, &target_name, seen)? {
            seen.pop();
            return Ok(true);
        }
    }
    seen.pop();
    Ok(false)
}

fn class_relation_subject_name(value: &Value) -> Option<String> {
    match value {
        Value::Reference(cell) => class_relation_subject_name(&cell.get()),
        Value::Object(object) => Some(normalize_class_name(&object.class_name())),
        Value::Fiber(_) => Some("fiber".to_owned()),
        Value::Callable(_) => Some("closure".to_owned()),
        _ => None,
    }
}

fn class_relation_config_fingerprint(compiled: &CompiledUnit) -> String {
    format!(
        "unit:{}:strict:{}",
        compiled.unit().id.raw(),
        compiled.unit().strict_types
    )
}

fn object_instanceof(
    compiled: &CompiledUnit,
    value: &Value,
    class_name: &str,
) -> Result<bool, String> {
    match value {
        Value::Reference(cell) => object_instanceof(compiled, &cell.get(), class_name),
        Value::Fiber(_) => Ok(normalize_class_name(class_name) == "fiber"),
        Value::Callable(_) => Ok(is_closure_runtime_class(class_name)),
        Value::Object(object) => {
            if is_std_class_runtime_class(&object.class_name())
                && is_std_class_runtime_class(class_name)
            {
                return Ok(true);
            }
            if let Some(result) = internal_throwable_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if class_is_or_implements(compiled, &object.class_name(), class_name)? {
                return Ok(true);
            }
            if let Some(spl_class) = spl_runtime_marker(object) {
                if let Some(result) = internal_spl_iterator_instanceof(&spl_class, class_name) {
                    return Ok(result);
                }
                if let Some(result) = internal_spl_container_instanceof(&spl_class, class_name) {
                    return Ok(result);
                }
                if let Some(result) = internal_spl_heap_instanceof(&spl_class, class_name) {
                    return Ok(result);
                }
                if let Some(result) = internal_spl_file_instanceof(&spl_class, class_name) {
                    return Ok(result);
                }
            }
            if let Some(result) = internal_spl_iterator_instanceof(&object.class_name(), class_name)
            {
                return Ok(result);
            }
            if let Some(result) =
                internal_spl_container_instanceof(&object.class_name(), class_name)
            {
                return Ok(result);
            }
            if let Some(result) = internal_spl_heap_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_spl_file_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_date_time_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_sqlite_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_pdo_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_mysqli_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_phar_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_zip_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_gd_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            class_is_or_implements(compiled, &object.class_name(), class_name)
        }
        _ => Ok(false),
    }
}

fn object_instanceof_in_state(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
    class_name: &str,
) -> Result<bool, String> {
    match value {
        Value::Reference(cell) => {
            object_instanceof_in_state(compiled, state, &cell.get(), class_name)
        }
        Value::Fiber(_) => Ok(normalize_class_name(class_name) == "fiber"),
        Value::Callable(_) => Ok(is_closure_runtime_class(class_name)),
        Value::Object(object) => {
            if let Some(result) = internal_throwable_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_spl_iterator_instanceof(&object.class_name(), class_name)
            {
                return Ok(result);
            }
            if let Some(result) =
                internal_spl_container_instanceof(&object.class_name(), class_name)
            {
                return Ok(result);
            }
            if let Some(result) = internal_spl_file_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_date_time_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_sqlite_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_pdo_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_mysqli_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_phar_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_zip_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            if let Some(result) = internal_gd_instanceof(&object.class_name(), class_name) {
                return Ok(result);
            }
            class_is_a_in_state(compiled, state, &object.class_name(), class_name)
        }
        _ => Ok(false),
    }
}

fn iterator_function_accepts_source(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
) -> Result<bool, String> {
    match effective_value(value) {
        Value::Array(_) => Ok(true),
        Value::Object(_) => object_instanceof_in_state(compiled, state, value, "Traversable"),
        _ => Ok(false),
    }
}

fn property_storage_name(
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> String {
    if property.flags.is_private {
        format!("private:{}:{}", class.display_name, property.name)
    } else {
        property.name.clone()
    }
}

#[cfg(feature = "jit-cranelift")]
fn property_load_pre_guard_status(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    value: &Value,
    metadata: &php_jit::JitPropertyLoadMetadata,
) -> Option<i32> {
    if state.lookup_epoch().raw() != metadata.layout_version {
        return Some(JIT_PROPERTY_LOAD_STATUS_LAYOUT_EXIT);
    }
    let effective = match value {
        Value::Reference(cell) => cell.get(),
        other => other.clone(),
    };
    let Value::Object(object) = effective else {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    };
    if normalize_class_name(&object.class_name()) != metadata.receiver_class {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    }
    let Some(class) = lookup_class_in_state(compiled, state, &object.class_name()) else {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    };
    if class.id.raw() != metadata.class_id {
        return Some(JIT_PROPERTY_LOAD_STATUS_CLASS_EXIT);
    }
    None
}

fn property_fetch_callsite(
    compiled: &CompiledUnit,
    function: FunctionId,
    block: BlockId,
    instruction: InstrId,
) -> String {
    let unit = compiled.unit();
    let function_name = unit
        .functions
        .get(function.index())
        .map(|entry| entry.name.as_str())
        .unwrap_or("<unknown>");
    format!(
        "unit{}:{}:b{}:i{}",
        unit.id.raw(),
        function_name,
        block.raw(),
        instruction.raw()
    )
}

fn method_call_callsite(
    compiled: &CompiledUnit,
    function: FunctionId,
    block: BlockId,
    instruction: InstrId,
) -> String {
    let unit = compiled.unit();
    let function_name = unit
        .functions
        .get(function.index())
        .map(|entry| entry.name.as_str())
        .unwrap_or("<unknown>");
    format!(
        "unit{}:{}:b{}:i{}",
        unit.id.raw(),
        function_name,
        block.raw(),
        instruction.raw()
    )
}

fn class_has_public_magic_get(compiled: &CompiledUnit, class: &php_ir::module::ClassEntry) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__get", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn class_has_public_magic_set(compiled: &CompiledUnit, class: &php_ir::module::ClassEntry) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__set", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn class_has_public_magic_call(
    compiled: &CompiledUnit,
    class: &php_ir::module::ClassEntry,
) -> bool {
    lookup_method_in_hierarchy(compiled, class, "__call", None)
        .ok()
        .flatten()
        .is_some_and(|resolved| {
            !resolved.method.flags.is_static
                && !resolved.method.flags.is_private
                && !resolved.method.flags.is_protected
        })
}

fn property_has_hooks_or_active(
    state: &ExecutionState,
    object: &ObjectRef,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> bool {
    property.hooks.get.is_some()
        || property.hooks.set.is_some()
        || property_hook_is_active(state, object, class, property)
}

#[allow(clippy::too_many_arguments)]
fn property_fetch_layout_metadata(
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_get: bool,
    has_property_hooks: bool,
    dynamic_property_fallback: bool,
    typed_property_initialized: bool,
) -> PropertyFetchLayoutMetadata {
    PropertyFetchLayoutMetadata {
        class_id: receiver_class.id.raw(),
        layout_version: layout_version.raw(),
        property_slot_index: declaring_class
            .properties
            .iter()
            .position(|entry| entry.name == property.name)
            .map(|index| index as u32),
        visibility_context: visibility_context.map(str::to_owned),
        typed_property_initialized,
        has_property_hooks,
        has_magic_get,
        dynamic_property_fallback,
    }
}

#[allow(clippy::too_many_arguments)]
fn property_assign_layout_metadata(
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_set: bool,
    has_property_hooks: bool,
    dynamic_property_fallback: bool,
    reference_slot: bool,
) -> PropertyAssignLayoutMetadata {
    PropertyAssignLayoutMetadata {
        class_id: receiver_class.id.raw(),
        layout_version: layout_version.raw(),
        property_slot_index: declaring_class
            .properties
            .iter()
            .position(|entry| entry.name == property.name)
            .map(|index| index as u32),
        visibility_context: visibility_context.map(str::to_owned),
        typed_property: property.type_.is_some(),
        readonly_or_init_only: property.flags.is_readonly || declaring_class.flags.is_readonly,
        reference_slot,
        has_property_hooks,
        has_magic_set,
        dynamic_property_fallback,
    }
}

#[allow(clippy::too_many_arguments)]
fn property_fetch_profile_observation(
    callsite: &str,
    property: &str,
    receiver_class: &str,
    class: &php_ir::module::ClassEntry,
    declared_property: Option<(
        &php_ir::module::ClassEntry,
        &php_ir::module::ClassPropertyEntry,
    )>,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_get: bool,
    has_property_hook: bool,
    dynamic_property_fallback: bool,
    declared_visible_property: bool,
    uninitialized_typed_property: bool,
    non_eligible_reasons: Vec<&'static str>,
) -> PropertyFetchProfileObservation {
    let (declared_property_name, property_slot_index) =
        declared_property.map_or((None, None), |(declaring_class, property)| {
            (
                Some(property.name.clone()),
                declaring_class
                    .properties
                    .iter()
                    .position(|entry| entry.name == property.name),
            )
        });
    PropertyFetchProfileObservation {
        callsite: callsite.to_owned(),
        property: property.to_owned(),
        receiver_class: receiver_class.to_owned(),
        class_id: class.id.raw(),
        declared_property_name,
        visibility_context: visibility_context.map(str::to_owned),
        property_slot_index,
        class_layout_version: layout_version.raw(),
        has_magic_get,
        has_property_hook,
        dynamic_property_fallback,
        declared_visible_property,
        uninitialized_typed_property,
        non_eligible_reasons,
    }
}

#[allow(clippy::too_many_arguments)]
fn method_call_profile_observation(
    callsite: &str,
    method: &str,
    receiver_class: &str,
    class: &php_ir::module::ClassEntry,
    resolved_method: Option<(
        &CompiledUnit,
        &php_ir::module::ClassEntry,
        &php_ir::module::ClassMethodEntry,
    )>,
    visibility_context: Option<&str>,
    layout_version: InvalidationEpoch,
    has_magic_call: bool,
    magic_call_fallback: bool,
    simple_positional_arguments: bool,
    has_by_ref_argument: bool,
    callee_jit_eligible: bool,
    direct_vm_call_helper_available: bool,
    non_eligible_reasons: Vec<&'static str>,
) -> MethodCallProfileObservation {
    let (
        declaring_class,
        method_id,
        method_slot_index,
        method_is_final,
        method_is_private,
        method_is_static,
    ) = resolved_method.map_or(
        (None, None, None, false, false, false),
        |(_owner, declaring_class, method_entry)| {
            (
                Some(declaring_class.name.clone()),
                Some(method_entry.function.raw()),
                declaring_class.methods.iter().position(|entry| {
                    entry.name == method_entry.name && entry.function == method_entry.function
                }),
                method_entry.flags.is_final,
                method_entry.flags.is_private,
                method_entry.flags.is_static,
            )
        },
    );
    MethodCallProfileObservation {
        callsite: callsite.to_owned(),
        method: method.to_owned(),
        receiver_class: receiver_class.to_owned(),
        class_id: class.id.raw(),
        declaring_class,
        method_id,
        method_slot_index,
        visibility_context: visibility_context.map(str::to_owned),
        override_layout_version: layout_version.raw(),
        method_is_final,
        method_is_private,
        method_is_static,
        has_magic_call,
        magic_call_fallback,
        simple_positional_arguments,
        has_by_ref_argument,
        callee_jit_eligible,
        direct_vm_call_helper_available,
        non_eligible_reasons,
    }
}

fn method_call_args_are_simple_positional(args: &[IrCallArg]) -> bool {
    args.iter().all(|arg| arg.name.is_none() && !arg.unpack)
}

fn method_call_has_by_ref_argument(
    _args: &[IrCallArg],
    owner: Option<&CompiledUnit>,
    function: Option<FunctionId>,
) -> bool {
    let Some((owner, function)) = owner.zip(function) else {
        return false;
    };
    owner
        .unit()
        .functions
        .get(function.index())
        .is_some_and(|callee| callee.params.iter().any(|param| param.by_ref))
}

#[allow(clippy::too_many_arguments)]
fn method_call_guard_metadata(
    args: &[CallArgument],
    receiver_class: &php_ir::module::ClassEntry,
    declaring_class: &php_ir::module::ClassEntry,
    method_entry: &php_ir::module::ClassMethodEntry,
    visibility_context: Option<&str>,
    epoch: InvalidationEpoch,
    has_magic_call: bool,
    has_by_ref_argument: bool,
) -> MethodCallGuardMetadata {
    MethodCallGuardMetadata {
        receiver_class_id: receiver_class.id.raw(),
        class_layout_epoch: epoch.raw(),
        method_table_epoch: epoch.raw(),
        method_slot_index: declaring_class
            .methods
            .iter()
            .position(|entry| {
                entry.name == method_entry.name && entry.function == method_entry.function
            })
            .and_then(|index| index.try_into().ok()),
        visibility_context: visibility_context.map(str::to_owned),
        method_is_final: method_entry.flags.is_final,
        method_is_private: method_entry.flags.is_private,
        method_is_static: method_entry.flags.is_static,
        receiver_has_override: receiver_class.name == declaring_class.name
            && receiver_class.parent.is_some(),
        argument_shape: method_call_shape(args),
        by_ref_compatible: !has_by_ref_argument,
        has_magic_call,
    }
}

fn method_call_cache_target_owner<'a>(
    compiled: &'a CompiledUnit,
    state: &'a ExecutionState,
    target: &MethodCallCacheTarget,
) -> Option<&'a CompiledUnit> {
    match target {
        MethodCallCacheTarget::CurrentUnit { .. } => Some(compiled),
        MethodCallCacheTarget::DynamicUnit { unit_index, .. } => {
            state.dynamic_units.get(*unit_index)
        }
    }
}

fn method_direct_call_target_is_eligible(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    target: &MethodCallCacheTarget,
    class: &php_ir::module::ClassEntry,
    receiver_class: &str,
    args: &[IrCallArg],
    values: &[CallArgument],
    has_magic_call: bool,
    epoch: InvalidationEpoch,
) -> bool {
    let resolved = target.resolved_target();
    let guard = &resolved.guard;
    if target.receiver_class_id() != class.id.raw() || target.receiver_class() != receiver_class {
        return false;
    }
    if guard.class_layout_epoch != epoch.raw() || guard.method_table_epoch != epoch.raw() {
        return false;
    }
    if guard.has_magic_call != has_magic_call {
        return false;
    }
    if guard.argument_shape != method_call_shape(values) {
        return false;
    }
    if !method_call_args_are_simple_positional(args) {
        return false;
    }
    let owner = method_call_cache_target_owner(compiled, state, target);
    let Some(owner) = owner else {
        return false;
    };
    if method_call_has_by_ref_argument(args, Some(owner), Some(target.function())) {
        return false;
    }
    let Some(declaring_class) = owner.lookup_class(&resolved.declaring_class) else {
        return false;
    };
    let Some(method_entry) = declaring_class
        .methods
        .iter()
        .find(|method| method.function == resolved.function)
    else {
        return false;
    };
    if guard.method_slot_index
        != declaring_class
            .methods
            .iter()
            .position(|entry| {
                entry.name == method_entry.name && entry.function == method_entry.function
            })
            .and_then(|index| index.try_into().ok())
    {
        return false;
    }
    guard.method_is_final == method_entry.flags.is_final
        && guard.method_is_private == method_entry.flags.is_private
        && guard.method_is_static == method_entry.flags.is_static
        && guard.by_ref_compatible
}

fn method_callee_shape_is_jit_eligible(owner: &CompiledUnit, function: FunctionId) -> bool {
    owner
        .unit()
        .functions
        .get(function.index())
        .is_some_and(|callee| {
            !callee.flags.is_top_level
                && !callee.flags.is_closure
                && !callee.flags.is_generator
                && !callee.returns_by_ref
                && matches!(
                    callee.return_type.as_ref(),
                    None | Some(
                        IrReturnType::Int
                            | IrReturnType::String
                            | IrReturnType::Bool
                            | IrReturnType::Null
                    )
                )
                && callee.captures.is_empty()
                && callee.params.iter().all(|param| {
                    !param.by_ref
                        && !param.variadic
                        && param.default.is_none()
                        && matches!(
                            param.type_.as_ref(),
                            None | Some(
                                IrReturnType::Int
                                    | IrReturnType::String
                                    | IrReturnType::Bool
                                    | IrReturnType::Null
                            )
                        )
                })
        })
}

fn method_tiny_inline_rejection_reason(
    owner: &CompiledUnit,
    class: &php_ir::module::ClassEntry,
    method_entry: &php_ir::module::ClassMethodEntry,
    args: &[IrCallArg],
    has_magic_call: bool,
) -> Option<&'static str> {
    if has_magic_call {
        return Some("magic_call_present");
    }
    if method_entry.flags.is_static {
        return Some("static_method");
    }
    if !(method_entry.flags.is_final || method_entry.flags.is_private || class.flags.is_final) {
        return Some("not_final_or_private");
    }
    if !method_call_args_are_simple_positional(args) {
        return Some("named_or_unpacked_arguments");
    }
    let Some(function) = owner.unit().functions.get(method_entry.function.index()) else {
        return Some("method_body_unavailable");
    };
    if function.flags.is_generator {
        return Some("generator_method");
    }
    if function.returns_by_ref
        || function
            .params
            .iter()
            .any(|param| param.by_ref || param.variadic)
    {
        return Some("refs_or_variadics");
    }
    if method_body_has_inline_blocker(function) {
        return Some("control_flow_or_escape");
    }
    if method_body_returns_scalar_constant(owner, function)
        || method_body_returns_this_property(function)
    {
        None
    } else {
        Some("not_tiny_leaf_return")
    }
}

fn method_body_has_inline_blocker(function: &IrFunction) -> bool {
    function.blocks.iter().any(|block| {
        block.instructions.iter().any(|instruction| {
            matches!(
                instruction.kind,
                InstructionKind::CallFunction { .. }
                    | InstructionKind::CallMethod { .. }
                    | InstructionKind::CallStaticMethod { .. }
                    | InstructionKind::CallClosure { .. }
                    | InstructionKind::CallCallable { .. }
                    | InstructionKind::Pipe { .. }
                    | InstructionKind::EnterTry { .. }
                    | InstructionKind::LeaveTry
                    | InstructionKind::EndFinally { .. }
                    | InstructionKind::Throw { .. }
                    | InstructionKind::Yield { .. }
                    | InstructionKind::YieldFrom { .. }
                    | InstructionKind::Include { .. }
                    | InstructionKind::Eval { .. }
                    | InstructionKind::AssignProperty { .. }
                    | InstructionKind::AssignPropertyDim { .. }
                    | InstructionKind::AssignStaticProperty { .. }
                    | InstructionKind::BindReferenceProperty { .. }
                    | InstructionKind::BindReferenceStaticProperty { .. }
                    | InstructionKind::UnsetProperty { .. }
                    | InstructionKind::UnsetPropertyDim { .. }
            )
        })
    })
}

fn method_body_returns_scalar_constant(owner: &CompiledUnit, function: &IrFunction) -> bool {
    let Some(block) = single_return_block(function) else {
        return false;
    };
    let Some(value) = block
        .terminator
        .as_ref()
        .and_then(|terminator| match terminator.kind {
            TerminatorKind::Return { value, .. } => value,
            _ => None,
        })
    else {
        return false;
    };
    match value {
        Operand::Constant(constant) => owner
            .unit()
            .constants
            .get(constant.index())
            .is_some_and(is_tiny_inline_scalar_constant),
        Operand::Register(register) => block.instructions.iter().any(|instruction| {
            matches!(
                instruction.kind,
                InstructionKind::LoadConst { dst, constant }
                    if dst == register
                        && owner
                            .unit()
                            .constants
                            .get(constant.index())
                            .is_some_and(is_tiny_inline_scalar_constant)
            )
        }),
        Operand::Local(_) => false,
    }
}

fn method_body_returns_this_property(function: &IrFunction) -> bool {
    let Some(block) = single_return_block(function) else {
        return false;
    };
    let Some(Operand::Register(return_register)) =
        block
            .terminator
            .as_ref()
            .and_then(|terminator| match terminator.kind {
                TerminatorKind::Return { value, .. } => value,
                _ => None,
            })
    else {
        return false;
    };
    block.instructions.iter().any(|instruction| {
        matches!(
            &instruction.kind,
            InstructionKind::FetchProperty {
                dst,
                object: Operand::Local(local),
                ..
            } if *dst == return_register
                && function
                    .locals
                    .get(local.index())
                    .is_some_and(|name| name == "this")
        )
    })
}

fn single_return_block(function: &IrFunction) -> Option<&php_ir::block::BasicBlock> {
    (function.blocks.len() == 1)
        .then(|| function.blocks.first())
        .flatten()
        .filter(|block| {
            matches!(
                block.terminator.as_ref().map(|terminator| &terminator.kind),
                Some(TerminatorKind::Return { .. })
            )
        })
}

fn is_tiny_inline_scalar_constant(constant: &IrConstant) -> bool {
    matches!(
        constant,
        IrConstant::Null
            | IrConstant::Bool(_)
            | IrConstant::Int(_)
            | IrConstant::Float(_)
            | IrConstant::String(_)
            | IrConstant::StringBytes(_)
    )
}

fn property_hook_is_active(
    state: &ExecutionState,
    object: &ObjectRef,
    class: &php_ir::module::ClassEntry,
    property: &php_ir::module::ClassPropertyEntry,
) -> bool {
    let class_name = normalize_class_name(&class.name);
    state.property_hook_stack.iter().any(|active| {
        active.object_id == object.id()
            && active.class_name == class_name
            && active.property == property.name
    })
}

fn normalize_method_name(method: &str) -> String {
    method.to_ascii_lowercase()
}

fn is_fiber_runtime_class(class_name: &str) -> bool {
    normalize_class_name(class_name) == "fiber"
}

fn is_closure_runtime_class(class_name: &str) -> bool {
    normalize_class_name(class_name) == "closure"
}

fn is_std_class_object(object: &ObjectRef) -> bool {
    normalize_class_name(&object.class_name()) == "stdclass"
}

fn closure_static_method_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    method: &str,
    args: Vec<CallArgument>,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Value, String> {
    match normalize_method_name(method).as_str() {
        "getcurrent" => {
            let values = call_args_to_positional("Closure::getCurrent", args)?;
            if !values.is_empty() {
                return Err(format!(
                    "E_PHP_VM_TOO_MANY_ARGS: Closure::getCurrent expects 0 argument(s), {} given",
                    values.len()
                ));
            }
            current_closure_value(compiled, state, stack)
        }
        "fromcallable" => {
            let mut values = call_args_to_positional("Closure::fromCallable", args)?;
            if values.len() != 1 {
                let id = if values.is_empty() {
                    "E_PHP_VM_TOO_FEW_ARGS"
                } else {
                    "E_PHP_VM_TOO_MANY_ARGS"
                };
                return Err(format!(
                    "{id}: Closure::fromCallable expects exactly 1 argument, {} given",
                    values.len()
                ));
            }
            let callable = resolve_closure_from_callable_relative_value(
                compiled,
                state,
                stack,
                values.remove(0),
                output,
                source_span,
            )?;
            let callable = acquire_callable_value(compiled, state, stack, callable)
                .map_err(closure_from_callable_error)?;
            Ok(closure_from_acquired_callable(callable))
        }
        "bind" => {
            let mut values = call_args_to_positional("Closure::bind", args)?;
            if values.len() < 2 {
                return Err(format!(
                    "E_PHP_VM_TOO_FEW_ARGS: Closure::bind expects at least 2 arguments, {} given",
                    values.len()
                ));
            }
            if values.len() > 3 {
                return Err(format!(
                    "E_PHP_VM_TOO_MANY_ARGS: Closure::bind expects at most 3 arguments, {} given",
                    values.len()
                ));
            }
            if let Some(scope) = values.get(2) {
                match callable_resolve_reference(scope.clone()) {
                    Value::Null | Value::String(_) | Value::Object(_) => {}
                    other => {
                        return Err(format!(
                            "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #3 ($newScope) must be of type object|string|null, {} given",
                            value_type_name(&other)
                        ));
                    }
                }
            }
            let closure = callable_resolve_reference(values.remove(0));
            let Value::Callable(callable) = closure else {
                return Err(format!(
                    "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #1 ($closure) must be of type Closure, {} given",
                    value_type_name(&closure)
                ));
            };
            let new_this = callable_resolve_reference(values.remove(0));
            let bound_this = match new_this {
                Value::Null => None,
                Value::Object(object) => Some(object),
                other => {
                    return Err(format!(
                        "E_PHP_VM_PARAM_TYPE_MISMATCH: Closure::bind(): Argument #2 ($newThis) must be of type ?object, {} given",
                        value_type_name(&other)
                    ));
                }
            };
            Ok(bind_closure_callable_value(callable, bound_this))
        }
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_METHOD: method Closure::{method} is not defined"
        )),
    }
}

fn bind_closure_callable_value(callable: CallableValue, bound_this: Option<ObjectRef>) -> Value {
    match callable {
        CallableValue::Closure(payload) => {
            let rebound_class = bound_this.as_ref().map(ObjectRef::class_name);
            let context = ClosureContext {
                owner_unit: payload.context.owner_unit,
                scope_class: rebound_class.clone().or(payload.context.scope_class),
                called_class: rebound_class.clone().or(payload.context.called_class),
                declaring_class: rebound_class.or(payload.context.declaring_class),
            };
            Value::closure(
                ClosurePayload::new(payload.function, payload.captures)
                    .with_debug(payload.debug.map(|debug| *debug))
                    .with_bound_this(bound_this.clone())
                    .with_context(context),
            )
        }
        CallableValue::BoundMethod {
            target,
            method,
            scope,
        } => {
            let rebound_target = match bound_this {
                Some(object) => CallableMethodTarget::Object(object),
                None => target,
            };
            Value::bound_method_callable(rebound_target, method, scope)
        }
        other => Value::Callable(other),
    }
}

fn callable_closure_should_warn_unbind_this(callable: &CallableValue) -> bool {
    let CallableValue::Closure(payload) = callable else {
        return false;
    };
    payload.bound_this.is_some()
        && payload
            .captures
            .iter()
            .any(|capture| capture.name == "this")
}

fn closure_from_acquired_callable(callable: Value) -> Value {
    match callable {
        Value::String(name) => {
            let name = name.to_string_lossy();
            if let Some((class_name, method)) = name.split_once("::") {
                Value::bound_method_callable(
                    CallableMethodTarget::Class(class_name.to_owned()),
                    method.to_owned(),
                    None,
                )
            } else if is_callable_builtin_name(&normalize_function_name(&name)) {
                Value::internal_builtin_callable(normalize_function_name(&name))
            } else {
                Value::user_function_callable(normalize_function_name(&name))
            }
        }
        other => other,
    }
}

fn closure_from_callable_error(message: String) -> String {
    let (id, reason) = message
        .split_once(": ")
        .filter(|(id, _)| id.starts_with("E_"))
        .map_or(
            (
                "E_PHP_VM_FIRST_CLASS_CALLABLE_NOT_CALLABLE",
                message.as_str(),
            ),
            |(id, reason)| (id, reason),
        );
    let mut reason = reason.to_owned();
    if let Some(first) = reason.get_mut(0..1) {
        first.make_ascii_lowercase();
    }
    format!("{id}: Failed to create closure from callable: {reason}")
}

fn resolve_closure_from_callable_relative_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    value: Value,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Value, String> {
    match value {
        Value::String(name) => {
            let name_text = name.to_string_lossy();
            let Some(resolved) = resolve_relative_callable_value(
                compiled,
                state,
                stack,
                &name_text,
                output,
                source_span,
            )?
            else {
                return Ok(Value::String(name));
            };
            Ok(resolved)
        }
        Value::Array(array) => {
            let mut resolved = PhpArray::new();
            for (key, value) in array.iter() {
                let value = if key == &ArrayKey::Int(0) {
                    match effective_value(value) {
                        Value::String(class_name) => resolve_relative_callable_class_name(
                            compiled,
                            state,
                            stack,
                            &class_name.to_string_lossy(),
                            output,
                            source_span.clone(),
                        )?
                        .map(Value::string)
                        .unwrap_or_else(|| value.clone()),
                        _ => value.clone(),
                    }
                } else {
                    value.clone()
                };
                resolved.insert(key.clone(), value);
            }
            Ok(Value::Array(resolved))
        }
        other => Ok(other),
    }
}

fn resolve_relative_callable_value(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    name: &str,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Option<Value>, String> {
    let Some((class_name, method)) = name.split_once("::") else {
        return Ok(None);
    };
    let Some(resolved_class) = resolve_relative_callable_class_name(
        compiled,
        state,
        stack,
        class_name,
        output,
        source_span,
    )?
    else {
        return Ok(None);
    };
    if let Some(object) = current_this_object(compiled, stack)
        && lookup_resolved_method_in_state(compiled, state, &resolved_class, method, None)?
            .is_some_and(|resolved| !resolved.method.flags.is_static)
    {
        validate_object_method_callable_acquisition(
            compiled,
            state,
            stack,
            &object.class_name(),
            method,
            true,
        )?;
        return Ok(Some(Value::bound_method_callable(
            CallableMethodTarget::Object(object),
            method.to_owned(),
            current_scope_class(compiled, stack),
        )));
    }
    Ok(Some(Value::string(format!("{resolved_class}::{method}"))))
}

fn resolve_relative_callable_class_name(
    compiled: &CompiledUnit,
    state: &mut ExecutionState,
    stack: &CallStack,
    class_name: &str,
    output: &mut OutputBuffer,
    source_span: RuntimeSourceSpan,
) -> Result<Option<String>, String> {
    match normalize_class_name(class_name).as_str() {
        "self" => {
            emit_relative_callable_deprecation(compiled, output, stack, state, "self", source_span);
            current_scope_class(compiled, stack)
                .ok_or_else(|| {
                    "E_PHP_VM_INVALID_STATIC_SCOPE: self:: is not available outside class scope"
                        .to_owned()
                })
                .map(Some)
        }
        "static" => {
            emit_relative_callable_deprecation(
                compiled,
                output,
                stack,
                state,
                "static",
                source_span,
            );
            current_called_class(compiled, stack)
                .ok_or_else(|| {
                    "E_PHP_VM_INVALID_STATIC_SCOPE: static:: is not available outside class scope"
                        .to_owned()
                })
                .map(Some)
        }
        "parent" => {
            emit_relative_callable_deprecation(
                compiled,
                output,
                stack,
                state,
                "parent",
                source_span,
            );
            let scope = current_scope_class(compiled, stack).ok_or_else(|| {
                "E_PHP_VM_INVALID_STATIC_SCOPE: parent:: is not available outside class scope"
                    .to_owned()
            })?;
            let class = lookup_class_in_state(compiled, state, &scope)
                .ok_or_else(|| format!("E_PHP_VM_UNKNOWN_CLASS: class {scope} is not defined"))?;
            class
                .parent
                .clone()
                .ok_or_else(|| {
                    format!(
                        "E_PHP_VM_NO_PARENT_CLASS: class {} has no parent",
                        class.name
                    )
                })
                .map(Some)
        }
        _ => Ok(None),
    }
}

fn emit_relative_callable_deprecation(
    compiled: &CompiledUnit,
    output: &mut OutputBuffer,
    stack: &CallStack,
    state: &mut ExecutionState,
    keyword: &str,
    source_span: RuntimeSourceSpan,
) {
    if !error_reporting_allows(state, php_runtime::PHP_E_DEPRECATED) {
        return;
    }
    let diagnostic = RuntimeDiagnostic::new(
        "E_PHP_VM_RELATIVE_CALLABLE_DEPRECATED",
        RuntimeSeverity::Deprecation,
        format!("Use of \"{keyword}\" in callables is deprecated"),
        source_span,
        stack_trace(compiled, stack),
        None,
    );
    emit_vm_diagnostic(
        output,
        state,
        &diagnostic,
        php_runtime::PhpDiagnosticChannel::Deprecated,
        php_runtime::PHP_E_DEPRECATED,
    );
    state.diagnostics.push(diagnostic);
}

fn current_closure_value(
    compiled: &CompiledUnit,
    state: &ExecutionState,
    stack: &CallStack,
) -> Result<Value, String> {
    let frame = stack
        .current()
        .ok_or_else(|| "E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned())?;
    let function = compiled
        .unit()
        .functions
        .get(frame.function.index())
        .ok_or_else(|| "E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned())?;
    if !function.flags.is_closure {
        return Err("E_PHP_VM_CURRENT_CLOSURE: Current function is not a closure".to_owned());
    }

    let mut captures = Vec::with_capacity(function.captures.len());
    for metadata in &function.captures {
        let slot = frame
            .locals
            .iter()
            .find(|(index, _)| *index == metadata.local.index())
            .map(|(_, slot)| slot)
            .ok_or_else(|| format!("invalid local local:{}", metadata.local.raw()))?;
        if metadata.by_ref {
            let Slot::Reference(cell) = slot else {
                return Err(format!(
                    "E_PHP_VM_BY_REF_CAPTURE_MISSING_CELL: closure capture ${} has no reference cell",
                    metadata.name
                ));
            };
            captures.push(ClosureCaptureValue::by_reference(
                metadata.name.clone(),
                cell.clone(),
            ));
        } else {
            captures.push(ClosureCaptureValue::by_value(
                metadata.name.clone(),
                slot.read(),
            ));
        }
    }

    let bound_this = (!function.flags.is_static)
        .then(|| current_this_object(compiled, stack))
        .flatten();
    Ok(Value::closure(
        ClosurePayload::new(frame.function.raw(), captures)
            .with_debug(closure_debug_info(compiled, frame.function))
            .with_bound_this(bound_this)
            .with_context(ClosureContext {
                owner_unit: dynamic_unit_index_for_compiled(state, compiled),
                scope_class: current_scope_class(compiled, stack),
                called_class: current_called_class(compiled, stack),
                declaring_class: current_scope_class(compiled, stack),
            }),
    ))
}

fn is_std_class_runtime_class(class_name: &str) -> bool {
    class_name
        .trim_start_matches('\\')
        .rsplit('\\')
        .next()
        .unwrap_or(class_name)
        .eq_ignore_ascii_case("stdclass")
}

fn is_php_token_runtime_class(class_name: &str) -> bool {
    normalize_class_name(class_name) == "phptoken"
}

fn php_token_static_method_value(
    class_name: &str,
    method: &str,
    args: Vec<CallArgument>,
) -> Result<Value, String> {
    match normalize_method_name(method).as_str() {
        "tokenize" => {
            let values = call_args_to_positional("PhpToken::tokenize", args)?;
            if values.is_empty() || values.len() > 2 {
                return Err(format!(
                    "E_PHP_VM_TOKENIZER_ARITY: {class_name}::tokenize expects 1 or 2 argument(s), {} given",
                    values.len()
                ));
            }
            let source = to_string(&values[0])?.to_string_lossy();
            let flags = values.get(1).map(to_int).transpose()?.unwrap_or(0);
            let tokens = php_runtime::tokenizer::tokenize(&source, flags)
                .map_err(|error| error.display_message())?;
            Ok(Value::packed_array(
                tokens
                    .into_iter()
                    .map(|token| Value::Object(php_token_object(token)))
                    .collect(),
            ))
        }
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_METHOD: method {class_name}::{method} is not defined"
        )),
    }
}

fn php_token_method_value(
    object: &ObjectRef,
    method: &str,
    args: Vec<Value>,
) -> Result<Value, String> {
    match normalize_method_name(method).as_str() {
        "gettokenname" => {
            if !args.is_empty() {
                return Err(format!(
                    "E_PHP_VM_TOKENIZER_ARITY: PhpToken::getTokenName expects 0 argument(s), {} given",
                    args.len()
                ));
            }
            Ok(object.get_property("name").unwrap_or(Value::Bool(false)))
        }
        "isignorable" => {
            if !args.is_empty() {
                return Err(format!(
                    "E_PHP_VM_TOKENIZER_ARITY: PhpToken::isIgnorable expects 0 argument(s), {} given",
                    args.len()
                ));
            }
            Ok(object
                .get_property("__ignorable")
                .unwrap_or(Value::Bool(false)))
        }
        "is" => {
            if args.len() != 1 {
                return Err(format!(
                    "E_PHP_VM_TOKENIZER_ARITY: PhpToken::is expects 1 argument(s), {} given",
                    args.len()
                ));
            }
            Ok(Value::Bool(php_token_matches_kind(object, &args[0])?))
        }
        "__tostring" => {
            if !args.is_empty() {
                return Err(format!(
                    "E_PHP_VM_TOKENIZER_ARITY: PhpToken::__toString expects 0 argument(s), {} given",
                    args.len()
                ));
            }
            Ok(object
                .get_property("text")
                .unwrap_or_else(|| Value::string(Vec::new())))
        }
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_METHOD: method {}::{} is not defined",
            object.class_name(),
            method
        )),
    }
}

fn php_token_matches_kind(object: &ObjectRef, kind: &Value) -> Result<bool, String> {
    match kind {
        Value::Reference(cell) => php_token_matches_kind(object, &cell.get()),
        Value::Int(value) => Ok(object.get_property("id") == Some(Value::Int(*value))),
        Value::String(value) => {
            let candidate = value.to_string_lossy();
            let text = object
                .get_property("text")
                .and_then(|value| match value {
                    Value::String(text) => Some(text.to_string_lossy()),
                    _ => None,
                })
                .unwrap_or_default();
            let name = object
                .get_property("name")
                .and_then(|value| match value {
                    Value::String(name) => Some(name.to_string_lossy()),
                    _ => None,
                })
                .unwrap_or_default();
            Ok(candidate == text || candidate.eq_ignore_ascii_case(&name))
        }
        Value::Array(array) => {
            for (_, value) in array.iter() {
                if php_token_matches_kind(object, value)? {
                    return Ok(true);
                }
            }
            Ok(false)
        }
        other => Err(format!(
            "E_PHP_VM_TOKENIZER_KIND_TYPE: PhpToken::is expects int|string|array, {} given",
            value_type_name(other)
        )),
    }
}

fn php_token_object(token: php_runtime::tokenizer::TokenizerToken) -> ObjectRef {
    let object = ObjectRef::new_with_display_name(&php_token_class(), "PhpToken");
    object.set_property("id", Value::Int(token.id));
    object.set_property("text", Value::string(token.text.into_bytes()));
    object.set_property("line", Value::Int(i64::from(token.line)));
    object.set_property("pos", Value::Int(i64::from(token.pos)));
    object.set_property("name", Value::String(PhpString::from_test_str(&token.name)));
    object.set_property(
        "__ignorable",
        Value::Bool(php_runtime::tokenizer::is_ignorable_name(token.token_name)),
    );
    object
}

fn php_token_class() -> RuntimeClassEntry {
    RuntimeClassEntry {
        name: normalize_class_name("PhpToken"),
        parent: None,
        interfaces: Vec::new(),
        methods: Vec::new(),
        properties: Vec::new(),
        constants: Vec::new(),
        enum_cases: Vec::new(),
        attributes: Vec::new(),
        enum_backing_type: None,
        constructor_id: None,
        flags: RuntimeClassFlags::default(),
    }
}

fn is_date_time_runtime_class(class_name: &str) -> bool {
    matches!(
        normalize_class_name(class_name).as_str(),
        "datetime" | "datetimeimmutable" | "datetimezone" | "dateinterval"
    )
}

fn internal_date_time_class_entry(normalized: &str) -> php_ir::module::ClassEntry {
    let normalized = normalize_class_name(normalized);
    let display_name = match normalized.as_str() {
        "datetimeinterface" => "DateTimeInterface",
        "datetime" => "DateTime",
        "datetimeimmutable" => "DateTimeImmutable",
        "datetimezone" => "DateTimeZone",
        "dateinterval" => "DateInterval",
        _ => "DateTime",
    };
    let mut entry =
        empty_internal_class_entry(display_name, None, None, normalized == "datetimeinterface");
    if matches!(normalized.as_str(), "datetime" | "datetimeimmutable") {
        entry
            .interfaces
            .push(normalize_class_name("DateTimeInterface"));
    }
    entry
}

fn internal_date_time_instanceof(object_class: &str, target_class: &str) -> Option<bool> {
    if !is_date_time_runtime_class(object_class) {
        return None;
    }
    let object_class = normalize_class_name(object_class);
    let target_class = normalize_class_name(target_class);
    Some(match target_class.as_str() {
        "datetimeinterface" => matches!(object_class.as_str(), "datetime" | "datetimeimmutable"),
        "datetime" => object_class == "datetime",
        "datetimeimmutable" => object_class == "datetimeimmutable",
        "datetimezone" => object_class == "datetimezone",
        "dateinterval" => object_class == "dateinterval",
        _ => false,
    })
}

fn new_date_time_object(
    class_name: &str,
    args: Vec<CallArgument>,
    default_timezone: &str,
) -> Result<ObjectRef, String> {
    let function = format!("{}::__construct", date_time_display_name(class_name));
    let values = call_args_to_positional(&function, args)?;
    match normalize_class_name(class_name).as_str() {
        "datetime" | "datetimeimmutable" => {
            validate_date_time_arg_count(&function, values.len(), 0, 2)?;
            let text = values
                .first()
                .map(to_string)
                .transpose()?
                .map(|value| value.to_string_lossy())
                .unwrap_or_else(|| "now".to_owned());
            let timezone = values
                .get(1)
                .map(date_time_timezone_name_from_value)
                .transpose()?
                .unwrap_or_else(|| default_timezone.to_owned());
            let base = php_runtime::datetime::current_timestamp();
            let timestamp =
                php_runtime::datetime::parse_datetime_text_in_timezone(&text, base, &timezone)
                    .ok_or_else(|| {
                        format!("E_PHP_VM_DATETIME_PARSE: could not parse DateTime text {text:?}")
                    })?;
            let value = if normalize_class_name(class_name) == "datetimeimmutable" {
                php_runtime::datetime::datetime_immutable_object(timestamp, &timezone)
            } else {
                php_runtime::datetime::datetime_object(timestamp, &timezone)
            };
            date_time_object_from_value(value)
        }
        "datetimezone" => {
            validate_date_time_arg_count(&function, values.len(), 1, 1)?;
            let timezone = to_string(&values[0])?.to_string_lossy();
            php_runtime::datetime::datetimezone_object(&timezone)
                .ok_or_else(|| {
                    format!("E_PHP_VM_DATETIMEZONE_INVALID: timezone {timezone:?} is unsupported")
                })
                .and_then(date_time_object_from_value)
        }
        "dateinterval" => {
            validate_date_time_arg_count(&function, values.len(), 1, 1)?;
            let spec = to_string(&values[0])?.to_string_lossy();
            let seconds = php_runtime::datetime::parse_interval_spec(&spec).ok_or_else(|| {
                format!("E_PHP_VM_DATEINTERVAL_PARSE: interval spec {spec:?} is unsupported")
            })?;
            date_time_object_from_value(php_runtime::datetime::dateinterval_object(seconds))
        }
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_CLASS: class {class_name} is not defined"
        )),
    }
}

fn call_date_time_method(
    object: ObjectRef,
    method: &str,
    args: Vec<CallArgument>,
) -> Result<Value, String> {
    let class_name = object.class_name();
    let function = format!("{}::{}", date_time_display_name(&class_name), method);
    let values = call_args_to_positional(&function, args)?;
    match normalize_class_name(&class_name).as_str() {
        "datetime" | "datetimeimmutable" => {
            let immutable = normalize_class_name(&class_name) == "datetimeimmutable";
            call_date_time_like_method(object, method, values, immutable)
        }
        "datetimezone" => call_date_timezone_method(object, method, values),
        "dateinterval" => call_date_interval_method(object, method, values),
        _ => Err(format!(
            "E_PHP_VM_UNKNOWN_METHOD: method {class_name}::{method} is not defined"
        )),
    }
}

